     1→import React, { useState, useEffect, useCallback, memo } from 'react';
     2→import { useDraggable } from '@dnd-kit/core';
     3→import { CSS } from '@dnd-kit/utilities';
     4→import { Paperclip } from 'lucide-react';
     5→import { useKanbanStore } from '../../stores/useKanbanStore';
     6→import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
     7→import { useSettingsStore } from '../../stores/useSettingsStore';
     8→import { ConfirmDialog } from '../../components/ConfirmDialog';
     9→import { CustomFieldDisplay } from '../../components/CustomFieldDisplay';
    10→import type { Task } from '../../types';
    11→
    12→interface KanbanCardProps {
    13→  task: Task;
    14→  isDragging?: boolean;
    15→  isSelected?: boolean;
    16→  onRegisterRef?: (ref: { triggerEdit: () => void }) => void;
    17→  onCardClick?: (task: Task, tab?: 'subtasks' | 'checklist' | 'comments' | 'activity') => void;
    18→}
    19→
    20→const KanbanCardComponent: React.FC<KanbanCardProps> = ({
    21→  task,
    22→  isDragging = false,
    23→  isSelected = false,
    24→  onRegisterRef,
    25→  onCardClick,
    26→}) => {
    27→  const { updateTask, deleteTask, archiveTask, getBlockers, getBlocked, getCriticalPath, getOverdueBlockers } = useKanbanStore();
    28→  const { getTotalTimeForCard, activeEntry } = useTimeTrackingStore();
    29→  const members = useSettingsStore((state) => state.members);
    30→  const taskFieldDefinitions = useSettingsStore((state) => state.customFieldDefinitions.tasks);
    31→
    32→  // Phase 1.3: Check if this task is on critical path
    33→  const isCritical = getCriticalPath().includes(task.id);
    34→
    35→  // P1: Get overdue blockers for dependency warnings
    36→  const overdueBlockers = getOverdueBlockers(task.id);
    37→
    38→  // Phase 3.1: Get assigned members
    39→  const assignedMembers = (task.assignees || [])
    40→    .map(id => members.find(m => m.id === id))
    41→    .filter(Boolean) as typeof members;
    42→  const [showMenu, setShowMenu] = useState(false);
    43→  const [isEditing, setIsEditing] = useState(false);
    44→  const [isDeleting, setIsDeleting] = useState(false);
    45→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
    46→
    47→  // Get total time logged for this card
    48→  const totalSeconds = getTotalTimeForCard(task.id);
    49→  const hasTimeTracked = totalSeconds > 0;
    50→  const isTimerActive = activeEntry?.taskId === task.id;
    51→  const [editedTask, setEditedTask] = useState({
    52→    title: task.title,
    53→    description: task.description,
    54→    priority: task.priority,
    55→    startDate: task.startDate || '',
    56→    dueDate: task.dueDate || '',
    57→  });
    58→
    59→  // Register ref for keyboard shortcut access
    60→  useEffect(() => {
    61→    if (onRegisterRef) {
    62→      onRegisterRef({
    63→        triggerEdit: () => setIsEditing(true),
    64→      });
    65→    }
    66→  }, [onRegisterRef]);
    67→
    68→  const { attributes, listeners, setNodeRef, transform } = useDraggable({
    69→    id: task.id,
    70→    disabled: isEditing,
    71→  });
    72→
    73→  const style = transform
    74→    ? {
    75→        transform: CSS.Translate.toString(transform),
    76→      }
    77→    : undefined;
    78→
    79→  const priorityColors = {
    80→    low: 'border-l-status-info',
    81→    medium: 'border-l-status-warning',
    82→    high: 'border-l-status-error',
    83→  };
    84→
    85→  const priorityLabels = {
    86→    low: 'Low',
    87→    medium: 'Med',
    88→    high: 'High',
    89→  };
    90→
    91→  // Format seconds to hours with 1 decimal (e.g., "2.5h")
    92→  const formatTime = (seconds: number): string => {
    93→    const hours = seconds / 3600;
    94→    return hours < 0.1 ? '<0.1h' : `${hours.toFixed(1)}h`;
    95→  };
    96→
    97→  // Get custom fields that are visible in cards and have values for this task
    98→  const activeCustomFields = task.customFields
    99→    ? taskFieldDefinitions
   100→        .filter(field => {
   101→          // Check visibility flag (default to true for backward compatibility)
   102→          const isVisible = field.visibleInCard !== false;
   103→          const value = task.customFields?.[field.id];
   104→          const hasValue = value !== null && value !== undefined && value !== '';
   105→          return isVisible && hasValue;
   106→        })
   107→        .map(field => ({
   108→          field,
   109→          value: task.customFields![field.id]
   110→        }))
   111→    : [];
   112→
   113→  const handleSave = useCallback(() => {
   114→    updateTask(task.id, {
   115→      title: editedTask.title.trim() || task.title,
   116→      description: editedTask.description,
   117→      priority: editedTask.priority,
   118→      startDate: editedTask.startDate || null,
   119→      dueDate: editedTask.dueDate || null,
   120→    });
   121→    setIsEditing(false);
   122→    setShowMenu(false);
   123→  }, [task.id, task.title, editedTask, updateTask]);
   124→
   125→  const handleDelete = useCallback(() => {
   126→    setIsDeleting(true);
   127→    setShowDeleteDialog(true);
   128→    setShowMenu(false);
   129→  }, []);
   130→
   131→  const confirmDelete = useCallback(() => {
   132→    deleteTask(task.id);
   133→    setShowDeleteDialog(false);
   134→  }, [task.id, deleteTask]);
   135→
   136→  const cancelDelete = useCallback(() => {
   137→    setShowDeleteDialog(false);
   138→    setIsDeleting(false);
   139→  }, []);
   140→
   141→  const handleArchive = useCallback(() => {
   142→    archiveTask(task.id);
   143→    setShowMenu(false);
   144→  }, [task.id, archiveTask]);
   145→
   146→  const handleCardClick = useCallback(() => {
   147→    if (!isDeleting && onCardClick) {
   148→      onCardClick(task);
   149→    }
   150→  }, [isDeleting, task, onCardClick]);
   151→
   152→  if (isEditing) {
   153→    return (
   154→      <div className="kanban-card-edit bg-surface-light dark:bg-surface-dark-elevated rounded-lg p-3 shadow-md border-2 border-accent-blue">
   155→        <input
   156→          type="text"
   157→          value={editedTask.title}
   158→          onChange={(e) => setEditedTask({ ...editedTask, title: e.target.value })}
   159→          placeholder="Task title"
   160→          className="w-full mb-2 px-2 py-1 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none"
   161→          autoFocus
   162→        />
   163→        <textarea
   164→          value={editedTask.description}
   165→          onChange={(e) => setEditedTask({ ...editedTask, description: e.target.value })}
   166→          placeholder="Description (optional)"
   167→          rows={2}
   168→          className="w-full mb-2 px-2 py-1 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue focus:outline-none resize-none"
   169→        />
   170→
   171→        <div className="grid grid-cols-2 gap-2 mb-2">
   172→          <div>
   173→            <label className="text-xs text-text-light-secondary dark:text-text-dark-secondary">Start Date</label>
   174→            <input
   175→              type="date"
   176→              value={editedTask.startDate}
   177→              onChange={(e) => setEditedTask({ ...editedTask, startDate: e.target.value })}
   178→              className="w-full px-2 py-1 text-xs border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary"
   179→            />
   180→          </div>
   181→          <div>
   182→            <label className="text-xs text-text-light-secondary dark:text-text-dark-secondary">Due Date</label>
   183→            <input
   184→              type="date"
   185→              value={editedTask.dueDate}
   186→              onChange={(e) => setEditedTask({ ...editedTask, dueDate: e.target.value })}
   187→              className="w-full px-2 py-1 text-xs border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary"
   188→            />
   189→          </div>
   190→        </div>
   191→
   192→        <div className="mb-2">
   193→          <label className="text-xs text-text-light-secondary dark:text-text-dark-secondary">Priority</label>
   194→          <select
   195→            value={editedTask.priority}
   196→            onChange={(e) =>
   197→              setEditedTask({ ...editedTask, priority: e.target.value as any })
   198→            }
   199→            className="w-full px-2 py-1 text-sm border border-border-light dark:border-border-dark rounded bg-surface-light dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary"
   200→          >
   201→            <option value="low">Low</option>
   202→            <option value="medium">Medium</option>
   203→            <option value="high">High</option>
   204→          </select>
   205→        </div>
   206→
   207→        <div className="flex gap-2">
   208→          <button
   209→            onClick={handleSave}
   210→            className="flex-1 px-3 py-1 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors"
   211→          >
   212→            Save
   213→          </button>
   214→          <button
   215→            onClick={() => setIsEditing(false)}
   216→            className="px-3 py-1 text-sm bg-neutral-600 text-white rounded hover:opacity-80 transition-opacity"
   217→          >
   218→            Cancel
   219→          </button>
   220→        </div>
   221→      </div>
   222→    );
   223→  }
   224→
   225→  // Phase 3.4: Get first image attachment for cover
   226→  const coverImage = task.attachments?.find(a => a.fileType.startsWith('image/'));
   227→  const coverMode = task.coverMode || 'fit';
   228→
   229→  return (
   230→    <div
   231→      ref={setNodeRef}
   232→      style={style}
   233→      {...listeners}
   234→      {...attributes}
   235→      onClick={handleCardClick}
   236→      className={`kanban-card bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-md border-l-4 ${
   237→        priorityColors[task.priority]
   238→      } cursor-grab active:cursor-grabbing hover:shadow-lg transition-all ${
   239→        isDragging ? 'opacity-50' : ''
   240→      } ${
   241→        isSelected ? 'ring-2 ring-accent-blue ring-offset-2 ring-offset-surface-light dark:ring-offset-surface-dark' : ''
   242→      } ${coverImage ? 'p-0' : 'p-3'} overflow-hidden rounded-lg`}
   243→    >
   244→      {/* Phase 3.4: Card Cover Image */}
   245→      {coverImage && (
   246→        <div className="relative w-full h-[120px] overflow-hidden rounded-t-lg">
   247→          <img
   248→            src={coverImage.dataUrl}
   249→            alt={coverImage.filename}
   250→            className={`w-full h-full ${
   251→              coverMode === 'fit'
   252→                ? 'object-contain bg-surface-light-elevated dark:bg-surface-dark-elevated'
   253→                : 'object-cover'
   254→            }`}
   255→            loading="lazy"
   256→          />
   257→        </div>
   258→      )}
   259→
   260→      <div className={coverImage ? 'p-3' : ''}>
   261→      <div className="flex items-start justify-between gap-2 mb-2">
   262→        <div className="flex-1">
   263→          {/* Phase A: Card Number */}
   264→          {task.cardNumber && (
   265→            <span className="text-xs font-mono text-text-light-secondary dark:text-text-dark-secondary mr-2">
   266→              KAN-{task.cardNumber}
   267→            </span>
   268→          )}
   269→          <h4 className="font-medium text-text-light-primary dark:text-text-dark-primary text-sm inline flex items-center gap-1.5">
   270→            {/* Phase 1.6: Milestone indicator */}
   271→            {task.isMilestone && (
   272→              <span className="shrink-0 text-sm" title="Milestone">📍</span>
   273→            )}
   274→            {task.title}
   275→          </h4>
   276→          {/* Phase 1.3: Critical path indicator */}
   277→          {isCritical && (
   278→            <span className="ml-1 inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-bold bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark border border-status-error-border dark:border-status-error-border-dark">
   279→              🔴 CRITICAL
   280→            </span>
   281→          )}
   282→          {/* P1: Overdue blocker warning */}
   283→          {overdueBlockers.length > 0 && (
   284→            <span
   285→              className="ml-1 inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark border border-status-warning-border dark:border-status-warning-border-dark"
   286→              title={`Blocked by ${overdueBlockers.length} overdue task${overdueBlockers.length > 1 ? 's' : ''}: ${overdueBlockers.map(b => b.title).join(', ')}`}
   287→            >
   288→              ⚠️ {overdueBlockers.length} overdue
   289→            </span>
   290→          )}
   291→        </div>
   292→        <div className="relative">
   293→          <button
   294→            onClick={(e) => {
   295→              e.stopPropagation();
   296→              setShowMenu(!showMenu);
   297→            }}
   298→            className="text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary p-1"
   299→          >
   300→            ⋮
   301→          </button>
   302→          {showMenu && (
   303→            <div className="absolute right-0 mt-1 bg-surface-light dark:bg-surface-dark-elevated border border-border-light dark:border-border-dark rounded shadow-lg z-10 min-w-[120px]">
   304→              <button
   305→                onClick={(e) => {
   306→                  e.stopPropagation(); // Prevent card click
   307→                  setIsEditing(true);
   308→                  setShowMenu(false);
   309→                }}
   310→                className="block w-full text-left px-4 py-2 text-sm hover:bg-surface-light-elevated dark:hover:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary"
   311→              >
   312→                Edit
   313→              </button>
   314→              <button
   315→                onClick={(e) => {
   316→                  e.stopPropagation(); // Prevent card click
   317→                  handleArchive();
   318→                }}
   319→                className="block w-full text-left px-4 py-2 text-sm hover:bg-surface-light-elevated dark:hover:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary"
   320→              >
   321→                📦 Archive
   322→              </button>
   323→              <button
   324→                onClick={(e) => {
   325→                  e.stopPropagation(); // Prevent card click
   326→                  handleDelete();
   327→                }}
   328→                className="block w-full text-left px-4 py-2 text-sm hover:bg-surface-light-elevated dark:hover:bg-neutral-800 text-status-error"
   329→              >
   330→                Delete
   331→              </button>
   332→            </div>
   333→          )}
   334→        </div>
   335→      </div>
   336→
   337→      {task.description && (
   338→        <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-2 line-clamp-2">
   339→          {task.description}
   340→        </p>
   341→      )}
   342→
   343→      <div className="flex items-center gap-2 flex-wrap">
   344→        {/* Priority Badge */}
   345→        <span className="text-xs px-2 py-0.5 rounded bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary">
   346→          {priorityLabels[task.priority]}
   347→        </span>
   348→
   349→        {/* Due Date with overdue/due soon indicators */}
   350→        {task.dueDate && (() => {
   351→          const dueDate = new Date(task.dueDate);
   352→          const now = new Date();
   353→          const daysUntilDue = Math.ceil((dueDate.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
   354→          const isOverdue = daysUntilDue < 0;
   355→          const isDueSoon = daysUntilDue >= 0 && daysUntilDue <= 3;
   356→
   357→          return (
   358→            <span className={`text-xs px-2 py-0.5 rounded ${
   359→              isOverdue
   360→                ? 'bg-status-error-bg dark:bg-status-error-bg-dark text-status-error-text dark:text-status-error-text-dark'
   361→                : isDueSoon
   362→                ? 'bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark'
   363→                : 'bg-neutral-100 dark:bg-neutral-800 text-accent-blue'
   364→            }`}>
   365→              📅 {dueDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}
   366→            </span>
   367→          );
   368→        })()}
   369→
   370→        {/* P1: Recurring Task Indicator */}
   371→        {(task.recurrence || task.recurrenceId) && (
   372→          <span
   373→            className="text-xs px-2 py-0.5 rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover font-medium"
   374→            title={
   375→              task.isRecurringParent
   376→                ? `Recurring task (${task.recurrence?.frequency})${task.nextOccurrence ? ` • Next: ${task.nextOccurrence}` : ''}`
   377→                : 'Instance of recurring task'
   378→            }
   379→          >
   380→            🔁 {task.isRecurringParent ? 'Recurring' : 'Instance'}
   381→          </span>
   382→        )}
   383→
   384→        {/* Estimated Hours */}
   385→        {task.estimatedHours && (
   386→          <span className="text-xs px-2 py-0.5 rounded bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary">
   387→            ⏱️ {task.estimatedHours}h
   388→          </span>
   389→        )}
   390→
   391→        {/* Time Tracked (Phase A: Time Tracking Integration) */}
   392→        {hasTimeTracked && (
   393→          <span
   394→            onClick={(e) => {
   395→              e.stopPropagation();
   396→              if (onCardClick) {
   397→                onCardClick(task);
   398→              }
   399→            }}
   400→            className={`text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 ${
   401→              isTimerActive
   402→                ? 'bg-accent-blue text-white hover:bg-accent-blue/90 animate-pulse'
   403→                : 'bg-neutral-100 dark:bg-neutral-800 text-accent-blue dark:text-accent-blue-hover'
   404→            }`}
   405→            title={isTimerActive ? 'Timer running - click to view' : 'Total time tracked - click to view'}
   406→          >
   407→            {isTimerActive && '⏱️ '}🕐 {formatTime(totalSeconds)}
   408→          </span>
   409→        )}
   410→
   411→        {/* Tags */}
   412→        {task.tags && task.tags.length > 0 && task.tags.map((tag) => (
   413→          <span
   414→            key={tag}
   415→            className="text-xs px-2 py-0.5 rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue dark:text-accent-blue-hover"
   416→          >
   417→            #{tag}
   418→          </span>
   419→        ))}
   420→
   421→        {/* Custom Fields (P1 Feature) */}
   422→        {activeCustomFields.map(({ field, value }) => (
   423→          <CustomFieldDisplay
   424→            key={field.id}
   425→            field={field}
   426→            value={value}
   427→            variant="card"
   428→          />
   429→        ))}
   430→
   431→        {/* Dependency Indicators (PHASE 5 PART 6) */}
   432→        {(() => {
   433→          const blockers = getBlockers(task.id);
   434→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   435→
   436→          if (incompleteBlockers.length > 0) {
   437→            return (
   438→              <span
   439→                onClick={(e) => {
   440→                  e.stopPropagation();
   441→                  if (onCardClick) {
   442→                    onCardClick(task);
   443→                  }
   444→                }}
   445→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-status-warning-bg dark:bg-status-warning-bg-dark text-status-warning-text dark:text-status-warning-text-dark hover:opacity-80"
   446→                title={`Blocked by ${incompleteBlockers.length} task(s)`}
   447→              >
   448→                🔒 Blocked by {incompleteBlockers.length}
   449→              </span>
   450→            );
   451→          }
   452→
   453→          const blocked = getBlocked(task.id);
   454→          if (blocked.length > 0) {
   455→            return (
   456→              <span
   457→                onClick={(e) => {
   458→                  e.stopPropagation();
   459→                  if (onCardClick) {
   460→                    onCardClick(task);
   461→                  }
   462→                }}
   463→                className="text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600"
   464→                title={`Blocking ${blocked.length} task(s)`}
   465→              >
   466→                ⚠️ Blocks {blocked.length}
   467→              </span>
   468→            );
   469→          }
   470→
   471→          return null;
   472→        })()}
   473→
   474→        {/* Subtask Progress Badge */}
   475→        {task.subtasks && task.subtasks.length > 0 && (() => {
   476→          const completedCount = task.subtasks.filter(st => st.completed).length;
   477→          const totalCount = task.subtasks.length;
   478→          const isComplete = completedCount === totalCount;
   479→
   480→          return (
   481→            <span
   482→              onClick={(e) => {
   483→                e.stopPropagation();
   484→                if (onCardClick) {
   485→                  onCardClick(task, 'subtasks');
   486→                }
   487→              }}
   488→              className={`text-xs px-2 py-0.5 rounded font-medium cursor-pointer transition-all hover:scale-105 ${
   489→                isComplete
   490→                  ? 'bg-status-success text-white hover:bg-status-success/90'
   491→                  : completedCount > 0
   492→                  ? 'bg-accent-blue text-white hover:bg-accent-blue/90'
   493→                  : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-300 dark:hover:bg-neutral-600'
   494→              }`}
   495→            >
   496→              ✓ {completedCount}/{totalCount} subtasks
   497→            </span>
   498→          );
   499→        })()}
   500→
   501→        {/* Assignee Avatars - Phase 3.1 */}
   502→        {assignedMembers.length > 0 && (
   503→          <div className="flex items-center -space-x-1.5">
   504→            {assignedMembers.slice(0, 3).map((member, index) => (
   505→              <div
   506→                key={member.id}
   507→                className="w-6 h-6 rounded-full flex items-center justify-center text-white font-bold text-[10px] border-2 border-surface-light dark:border-surface-dark-elevated shrink-0"
   508→                style={{
   509→                  backgroundColor: member.avatarColor,
   510→                  zIndex: assignedMembers.length - index
   511→                }}
   512→                title={member.name}
   513→              >
   514→                {member.initials}
   515→              </div>
   516→            ))}
