     1→import React, { useState, useMemo } from 'react';
     2→import { ConfirmDialog } from '../../components/ConfirmDialog';
     3→import { CustomFieldDisplay } from '../../components/CustomFieldDisplay';
     4→import { useKanbanStore } from '../../stores/useKanbanStore';
     5→import { useSettingsStore } from '../../stores/useSettingsStore';
     6→import type { Task, KanbanColumn, TaskPriority, TaskStatus } from '../../types';
     7→import type { FieldDefinition } from '../../types/customFields';
     8→
     9→interface ListViewProps {
    10→  tasks: Task[];
    11→  columns: KanbanColumn[];
    12→  onTaskClick: (task: Task) => void;
    13→}
    14→
    15→type SortColumn = 'title' | 'status' | 'priority' | 'dueDate' | null;
    16→type SortDirection = 'asc' | 'desc' | null;
    17→
    18→/**
    19→ * ListView Component
    20→ * Table format alternative to board view
    21→ *
    22→ * Features:
    23→ * - Sortable columns (title, status, priority, due date)
    24→ * - Bulk select with checkboxes
    25→ * - Bulk actions (change status, priority, delete)
    26→ * - Export to CSV
    27→ * - Row click opens detail panel
    28→ */
    29→export const ListView: React.FC<ListViewProps> = ({ tasks, columns, onTaskClick }) => {
    30→  const { bulkUpdateStatus, bulkUpdatePriority, bulkDeleteTasks } = useKanbanStore();
    31→  const taskFieldDefinitions = useSettingsStore((state) => state.customFieldDefinitions.tasks);
    32→
    33→  // Filter to only fields visible in list view
    34→  const visibleFieldDefinitions = useMemo(() => {
    35→    return taskFieldDefinitions.filter(field => field.visibleInList !== false);
    36→  }, [taskFieldDefinitions]);
    37→
    38→  // Sorting state
    39→  const [sortColumn, setSortColumn] = useState<SortColumn>(null);
    40→  const [sortDirection, setSortDirection] = useState<SortDirection>(null);
    41→
    42→  // Bulk selection state
    43→  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());
    44→
    45→  // Bulk action dialogs
    46→  const [showStatusDialog, setShowStatusDialog] = useState(false);
    47→  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
    48→  const [showDeleteDialog, setShowDeleteDialog] = useState(false);
    49→
    50→  // Handle column header click for sorting
    51→  const handleSort = (column: SortColumn) => {
    52→    if (sortColumn === column) {
    53→      // Cycle: asc → desc → null
    54→      if (sortDirection === 'asc') {
    55→        setSortDirection('desc');
    56→      } else if (sortDirection === 'desc') {
    57→        setSortColumn(null);
    58→        setSortDirection(null);
    59→      }
    60→    } else {
    61→      setSortColumn(column);
    62→      setSortDirection('asc');
    63→    }
    64→  };
    65→
    66→  // Sort tasks based on current sort state
    67→  const sortedTasks = useMemo(() => {
    68→    if (!sortColumn || !sortDirection) return tasks;
    69→
    70→    return [...tasks].sort((a, b) => {
    71→      let aValue: string | number | null = null;
    72→      let bValue: string | number | null = null;
    73→
    74→      switch (sortColumn) {
    75→        case 'title':
    76→          aValue = a.title.toLowerCase();
    77→          bValue = b.title.toLowerCase();
    78→          break;
    79→        case 'status':
    80→          aValue = columns.findIndex(col => col.id === a.status);
    81→          bValue = columns.findIndex(col => col.id === b.status);
    82→          break;
    83→        case 'priority':
    84→          const priorityOrder = { low: 0, medium: 1, high: 2 };
    85→          aValue = priorityOrder[a.priority];
    86→          bValue = priorityOrder[b.priority];
    87→          break;
    88→        case 'dueDate':
    89→          aValue = a.dueDate ? new Date(a.dueDate).getTime() : Infinity;
    90→          bValue = b.dueDate ? new Date(b.dueDate).getTime() : Infinity;
    91→          break;
    92→      }
    93→
    94→      if (aValue === null || aValue === undefined) return 1;
    95→      if (bValue === null || bValue === undefined) return -1;
    96→
    97→      if (aValue < bValue) return sortDirection === 'asc' ? -1 : 1;
    98→      if (aValue > bValue) return sortDirection === 'asc' ? 1 : -1;
    99→      return 0;
   100→    });
   101→  }, [tasks, sortColumn, sortDirection, columns]);
   102→
   103→  // Toggle select all
   104→  const handleSelectAll = (checked: boolean) => {
   105→    if (checked) {
   106→      setSelectedTaskIds(new Set(tasks.map(t => t.id)));
   107→    } else {
   108→      setSelectedTaskIds(new Set());
   109→    }
   110→  };
   111→
   112→  // Toggle individual task selection
   113→  const handleSelectTask = (taskId: string, checked: boolean) => {
   114→    const newSet = new Set(selectedTaskIds);
   115→    if (checked) {
   116→      newSet.add(taskId);
   117→    } else {
   118→      newSet.delete(taskId);
   119→    }
   120→    setSelectedTaskIds(newSet);
   121→  };
   122→
   123→  // Bulk actions
   124→  const handleBulkStatusChange = (status: TaskStatus) => {
   125→    bulkUpdateStatus(Array.from(selectedTaskIds), status);
   126→    setSelectedTaskIds(new Set());
   127→    setShowStatusDialog(false);
   128→  };
   129→
   130→  const handleBulkPriorityChange = (priority: TaskPriority) => {
   131→    bulkUpdatePriority(Array.from(selectedTaskIds), priority);
   132→    setSelectedTaskIds(new Set());
   133→    setShowPriorityDialog(false);
   134→  };
   135→
   136→  const handleBulkDelete = () => {
   137→    bulkDeleteTasks(Array.from(selectedTaskIds));
   138→    setSelectedTaskIds(new Set());
   139→    setShowDeleteDialog(false);
   140→  };
   141→
   142→  // Export CSV
   143→  const handleExportCSV = () => {
   144→    const customFieldHeaders = visibleFieldDefinitions.map(f => f.name);
   145→    const headers = ['Title', 'Status', 'Priority', 'Due Date', 'Tags', 'Subtask Progress', ...customFieldHeaders];
   146→    const rows = tasks.map(task => {
   147→      const statusColumn = columns.find(col => col.id === task.status);
   148→      const status = statusColumn?.title || task.status;
   149→      const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
   150→      const totalSubtasks = task.subtasks?.length || 0;
   151→      const progress = totalSubtasks > 0 ? `${completedSubtasks}/${totalSubtasks}` : 'N/A';
   152→
   153→      const customFieldValues = visibleFieldDefinitions.map(field => {
   154→        const value = task.customFields?.[field.id];
   155→        return formatCustomFieldValue(field, value);
   156→      });
   157→
   158→      return [
   159→        `"${task.title.replace(/"/g, '""')}"`, // Escape quotes
   160→        status,
   161→        task.priority,
   162→        task.dueDate || 'N/A',
   163→        task.tags.join('; '),
   164→        progress,
   165→        ...customFieldValues,
   166→      ];
   167→    });
   168→
   169→    const csv = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
   170→    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
   171→    const url = URL.createObjectURL(blob);
   172→    const link = document.createElement('a');
   173→    link.href = url;
   174→    link.download = `kanban-tasks-${new Date().toISOString().split('T')[0]}.csv`;
   175→    link.click();
   176→    URL.revokeObjectURL(url);
   177→  };
   178→
   179→  // Priority colors
   180→  const priorityColors = {
   181→    low: 'text-status-info',
   182→    medium: 'text-status-warning',
   183→    high: 'text-status-error',
   184→  };
   185→
   186→  // Format custom field value for CSV export
   187→  const formatCustomFieldValue = (field: FieldDefinition, value: any): string => {
   188→    if (value === null || value === undefined || value === '') return 'N/A';
   189→
   190→    switch (field.type) {
   191→      case 'date':
   192→        const date = new Date(value);
   193→        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
   194→      case 'checkbox':
   195→        return value ? 'Yes' : 'No';
   196→      case 'number':
   197→        return String(value);
   198→      case 'text':
   199→      case 'select':
   200→      default:
   201→        return String(value);
   202→    }
   203→  };
   204→
   205→  // Sort indicator
   206→  const getSortIndicator = (column: SortColumn) => {
   207→    if (sortColumn !== column) return null;
   208→    return sortDirection === 'asc' ? ' ▲' : ' ▼';
   209→  };
   210→
   211→  const allSelected = tasks.length > 0 && selectedTaskIds.size === tasks.length;
   212→  const someSelected = selectedTaskIds.size > 0 && selectedTaskIds.size < tasks.length;
   213→
   214→  return (
   215→    <div className="list-view">
   216→      {/* Bulk Actions Toolbar */}
