   598→              type="range"
   599→              min="0"
   600→              max="100"
   601→              step="5"
   602→              value={progress}
   603→              onChange={(e) => {
   604→                const newProgress = parseInt(e.target.value);
   605→                setProgress(newProgress);
   606→                handleFieldBlur('progress', newProgress);
   607→              }}
   608→              className="w-full h-2 bg-neutral-200 dark:bg-neutral-700 rounded-lg appearance-none cursor-pointer accent-accent-blue"
   609→            />
   610→
   611→            {/* Numeric input + quick-set buttons */}
   612→            <div className="flex items-center gap-2 mt-2">
   613→              <input
   614→                type="number"
   615→                min="0"
   616→                max="100"
   617→                value={progress}
