   623→                className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
   624→              />
   625→              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">%</span>
   626→
   627→              {/* Quick-set buttons */}
   628→              <div className="flex gap-1 ml-auto">
   629→                {[0, 25, 50, 75, 100].map((val) => (
   630→                  <button
   631→                    key={val}
   632→                    onClick={() => {
   633→                      setProgress(val);
   634→                      handleFieldBlur('progress', val);
   635→                    }}
   636→                    className={`px-2 py-1 text-xs rounded transition-colors ${
   637→                      progress === val
   638→                        ? 'bg-accent-blue text-white'
   639→                        : 'bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-200 dark:hover:bg-neutral-700'
   640→                    }`}
   641→                  >
   642→                    {val}%
   643→                  </button>
   644→                ))}
   645→              </div>
   646→            </div>
   647→          </div>
   648→
   649→          {/* Tags */}
   650→          <div>
   651→            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
   652→              Tags
   653→            </label>
   654→            <div className="flex flex-wrap gap-2 mb-2">
