   699→
   700→            {/* Show current recurrence or button to add */}
   701→            {!showRecurrencePicker && (
   702→              <div>
   703→                {task?.recurrence ? (
   704→                  <div className="space-y-2">
   705→                    {/* Recurrence Summary */}
   706→                    <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
   707→                      <div className="flex items-start justify-between gap-2">
   708→                        <div className="flex-1">
   709→                          <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
   710→                            {(() => {
   711→                              const { frequency, interval, daysOfWeek, dayOfMonth } = task.recurrence;
   712→                              let summary = 'Repeats ';
   713→
   714→                              // Frequency and interval
   715→                              if (interval === 1) {
   716→                                summary += frequency;
   717→                              } else {
   718→                                summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
   719→                              }
   720→
   721→                              // Days of week (for weekly)
   722→                              if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
   723→                                const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
   724→                                const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
   725→                                summary += ` on ${selectedDays}`;
