   737→                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   738→                              {task.recurrence.endType === 'after' && task.recurrence.endCount &&
   739→                                `Ends after ${task.recurrence.endCount} occurrences`
   740→                              }
   741→                              {task.recurrence.endType === 'until' && task.recurrence.endDate &&
