   769→                    className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
