   786→                    }
   787→                  }}
   788→                  onClose={() => setShowRecurrencePicker(false)}
   789→                />
   790→              </div>
   791→            )}
   792→          </div>
   793→
   794→          {/* P2: Save as Template */}
   795→          <div>
