   875→                onClick={() => setActiveTab('comments')}
   876→                className={`pb-1 px-1 text-xs font-medium transition-colors ${
   877→                  activeTab === 'comments'
   878→                    ? 'text-accent-blue border-b-2 border-accent-blue'
   879→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   880→                }`}
   881→              >
   882→                Comments
