   898→                    ? 'text-accent-blue border-b-2 border-accent-blue'
   899→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   900→                }`}
   901→              >
   902→                Time
   903→              </button>
   904→              <button
   905→                onClick={() => setActiveTab('attachments')}
   906→                className={`pb-1 px-1 text-xs font-medium transition-colors ${
