   908→                    ? 'text-accent-blue border-b-2 border-accent-blue'
   909→                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
   910→                }`}
   911→              >
   912→                Attachments {task.attachments && task.attachments.length > 0 && `(${task.attachments.length})`}
   913→              </button>
   914→            </div>
   915→          </div>
   916→
   917→          {/* Tab Content */}
   918→          <div className="py-2">
