import React, { useState, useEffect, useCallback } from 'react';
import { Modal } from '../../components/Modal';
import { RecurrencePicker } from '../../components/RecurrencePicker';
import { CustomFieldEditor } from '../../components/CustomFieldEditor';
import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
import AssigneePicker from '../../components/AssigneePicker';
import ImagePreviewModal from '../../components/ImagePreviewModal';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import { useTemplateStore } from '../../stores/useTemplateStore';
import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, TaskDependency, TaskAttachment } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

// Tab Components
import {
  ActivityTabContent,
  AttachmentsTabContent,
  ChecklistTabContent,
  CommentsTabContent,
  SubtasksTabContent,
  TimeTrackingTabContent,
} from './tabs';

// Section Components
import {
  TaskDatesSection,
  TaskDependenciesSection,
} from './sections';

/**
 * TaskCustomFields - Separate component to properly use hooks
 * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
 */
const TaskCustomFields: React.FC<{
  task: Task;
  onSave: (taskId: string, updates: Partial<Task>) => void;
}> = ({ task, onSave }) => {
  const { customFieldDefinitions } = useSettingsStore();
  const taskFields = customFieldDefinitions.tasks;

  if (taskFields.length === 0) return null;

  return (
    <div>
      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
        Custom Fields
      </label>
      <div className="space-y-3">
        {taskFields.map((field: FieldDefinition) => {
          const currentValue = task?.customFields?.[field.id];

          return (
            <div key={field.id}>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                {field.name}
                {field.required && (
                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
                )}
              </label>
              {field.description && (
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  {field.description}
                </p>
              )}
              <CustomFieldEditor
                field={field}
                value={currentValue}
                onChange={(value) => {
                  if (!task) return;
                  const updatedCustomFields = {
                    ...task.customFields,
                    [field.id]: value,
                  };
                  onSave(task.id, { customFields: updatedCustomFields });
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

interface CardDetailPanelProps {
  task: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (taskId: string, updates: Partial<Task>) => void;
  columns: Array<{ id: string; title: string; color: string }>;
  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
  onCardClick?: (task: Task) => void;
}

/**
 * Card Detail Panel
 * Full-screen modal for viewing and editing task details
 *
 * Features:
 * - Left side: Task metadata (title, description, dates, priority, tags, status)
 * - Right side: Tabs (Checklist, Comments, Activity Log)
 * - Inline editing (auto-save on blur)
 * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
 * - Tab persistence (remembers last active tab)
 * - Responsive design (mobile, tablet, desktop)
 */
export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
  task,
  isOpen,
  onClose,
  onSave,
  columns,
  initialTab,
  onCardClick,
}) => {
  // Kanban store actions
  const {
    tasks,
    addChecklistItem,
    updateChecklistItem,
    deleteChecklistItem,
    toggleChecklistItem,
    addComment,
    addSubtask,
    deleteSubtask,
    toggleSubtask,
    addDependency,
    removeDependency,
    getBlocked,
    updateEffort,
    updateCustomStatus,
    startTimer,
    stopTimer: stopKanbanTimer,
    updateTimeEstimate,
    setTaskRecurrence,
    applyDependentShifts,
    addAttachment,
    deleteAttachment,
  } = useKanbanStore();

  // Time tracking store (Phase A: Time Tracking Integration)
  const {
    getEntriesForCard,
    getTotalTimeForCard,
    startTimerForCard,
    stopTimer,
    activeEntry,
  } = useTimeTrackingStore();

  // Template store (P2: Task Templates)
  const { createTemplate } = useTemplateStore();

  // Tab state with persistence
  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
    if (initialTab) return initialTab;
    const saved = localStorage.getItem('kanban-detail-panel-tab');
    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
  });

  // Sync activeTab with initialTab when it changes
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Local state for editing (synced with task prop)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState<string | null>(null);
  const [dueDate, setDueDate] = useState<string | null>(null);
  const [priority, setPriority] = useState<TaskPriority>('medium');
  const [tags, setTags] = useState<string[]>([]);
  const [status, setStatus] = useState<TaskStatus>('todo');
  const [newTag, setNewTag] = useState('');
  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
  const [assignees, setAssignees] = useState<string[]>([]);
  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %

  // P1: Recurring tasks state
  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);

  // Phase 1.2: Auto-shift dependent tasks
  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);

  // Note: Checklist, Comment, and Subtask state moved to extracted tab components

  // Phase 3.2: Attachment state
  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);

  // Phase 2 Quick Wins: Inline date editing
  const [isEditingStartDate, setIsEditingStartDate] = useState(false);
  const [isEditingDueDate, setIsEditingDueDate] = useState(false);

  // No longer need local state for dependency selection - handled by DependencyPicker

  // Sync local state with task prop when task changes
  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description);
      setStartDate(task.startDate);
      setDueDate(task.dueDate);
      setPriority(task.priority);
      setTags(task.tags);
      setStatus(task.status);
      setEffort(task.effort);
      setCustomStatus(task.customStatus);
      setTimeEstimate(task.timeTracking?.estimated);
      setAssignees(task.assignees || []);
      setProgress(task.progress || 0); // Phase 1.5
    }
  }, [task]);

  // Tab persistence
  useEffect(() => {
    localStorage.setItem('kanban-detail-panel-tab', activeTab);
  }, [activeTab]);

  // Save and close handler
  const handleSaveAndClose = useCallback(() => {
    if (!task) return;
    onSave(task.id, {
      title,
      description,
      startDate,
      dueDate,
      priority,
      tags,
      status,
      assignees,
    });
    onClose();
  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status, assignees]);

  // Keyboard shortcut: Cmd+Enter to save and close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
        e.preventDefault();
        handleSaveAndClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, handleSaveAndClose]);

  if (!task) return null;

  const handleFieldBlur = (field: keyof Task, value: unknown) => {
    // Phase 1.2: Check if date change triggers dependent shifts
    if ((field === 'startDate' || field === 'dueDate') && task) {
      const oldStartDate = task.startDate;
      const oldDueDate = task.dueDate;
      const newStartDate = field === 'startDate' ? (value as string | null) : task.startDate;
      const newDueDate = field === 'dueDate' ? (value as string | null) : task.dueDate;

      // Check if auto-shift is enabled and dates actually changed
      if (shouldAutoShift(
        { ...task, startDate: newStartDate, dueDate: newDueDate },
        oldStartDate,
        oldDueDate,
        autoShiftDependentTasks
      )) {
        // Calculate what shifts would be needed
        const shifts = calculateDependentShifts(
          { ...task, startDate: newStartDate, dueDate: newDueDate },
          oldStartDate,
          oldDueDate,
          tasks
        );

        if (shifts.length > 0) {
          // Show confirmation dialog
          setPendingShifts(shifts);
          // Don't save yet - wait for user confirmation
          return;
        }
      }
    }

    // Auto-save on blur (normal case or no shifts needed)
    onSave(task.id, { [field]: value });
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      const updatedTags = [...tags, newTag.trim()];
      setTags(updatedTags);
      onSave(task.id, { tags: updatedTags });
      setNewTag('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    const updatedTags = tags.filter(tag => tag !== tagToRemove);
    setTags(updatedTags);
    onSave(task.id, { tags: updatedTags });
  };

  // Dependency handlers
  const handleAddDependency = (dependency: TaskDependency) => {
    if (!task) return;
    addDependency(task.id, dependency);
  };

  const handleRemoveDependency = (dependencyId: string) => {
    if (!task) return;
    removeDependency(task.id, dependencyId);
  };

  // Phase 1.2: Shift confirmation handlers
  const handleConfirmShifts = () => {
    if (!pendingShifts || !task) return;

    // Apply the date change to the current task first
    const dateField = startDate !== task.startDate ? 'startDate' : 'dueDate';
    const dateValue = startDate !== task.startDate ? startDate : dueDate;
    onSave(task.id, { [dateField]: dateValue });

    // Then apply all dependent shifts
    applyDependentShifts(pendingShifts);

    // Close dialog
    setPendingShifts(null);
  };

  const handleCancelShifts = () => {
    if (!task) return;

    // Revert local state to original values
    setStartDate(task.startDate);
    setDueDate(task.dueDate);

    // Close dialog
    setPendingShifts(null);
  };

  const handleDontAskAgain = () => {
    // Disable auto-shift
    setAutoShiftDependentTasks(false);

    // Close dialog without applying shifts
    handleCancelShifts();
  };

  // P2: Save task as template
  const handleSaveAsTemplate = () => {
    if (!task) return;

    // Check if task has content worth templating
    const hasContent = Boolean(
      task.description ||
      (task.checklist && task.checklist.length > 0) ||
      (task.customFields && Object.keys(task.customFields).length > 0)
    );

    if (!hasContent) {
      alert('Task must have description, checklist, or custom fields to save as template');
      return;
    }

    // Create template from current task
    const template = createTemplate(task);

    // Show success feedback
    alert(`Template "${template.name}" created successfully!`);
  };

  const availableTasks = tasks.filter(t => t.id !== task?.id);

  return (
    <>
    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
      <div className="flex flex-col md:flex-row gap-3 pr-1">
        {/* Left Side: Task Metadata (60%) */}
        <div className="w-full md:w-3/5 space-y-2">
          {/* Title */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Title
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={() => handleFieldBlur('title', title)}
              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onBlur={() => handleFieldBlur('description', description)}
              placeholder="Add a description..."
              className="w-full min-h-[48px] p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-xs text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
              rows={2}
            />
          </div>

          {/* Dates (Inline NL Editing) */}
          <TaskDatesSection
            task={task}
            startDate={startDate}
            setStartDate={setStartDate}
            dueDate={dueDate}
            setDueDate={setDueDate}
            isEditingStartDate={isEditingStartDate}
            setIsEditingStartDate={setIsEditingStartDate}
            isEditingDueDate={isEditingDueDate}
            setIsEditingDueDate={setIsEditingDueDate}
            onFieldBlur={handleFieldBlur}
          />

          {/* Priority */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Priority
            </label>
            <select
              value={priority}
              onChange={(e) => {
                const newPriority = e.target.value as TaskPriority;
                setPriority(newPriority);
                handleFieldBlur('priority', newPriority);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>

          {/* Milestone Checkbox - Phase 1.6 */}
          <div className="flex items-center gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
            <input
              type="checkbox"
              id="is-milestone"
              checked={task?.isMilestone || false}
              onChange={(e) => {
                const isMilestone = e.target.checked;
                handleFieldBlur('isMilestone', isMilestone);

                // If marking as milestone, clear start date (milestones are single-point events)
                if (isMilestone && task?.startDate) {
                  handleFieldBlur('startDate', null);
                  setStartDate(null);
                }
              }}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark text-accent-blue focus:ring-2 focus:ring-accent-blue cursor-pointer"
            />
            <label
              htmlFor="is-milestone"
              className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer select-none"
            >
              📍 Mark as Milestone (key deadline/deliverable)
            </label>
          </div>

          {/* Assignees - Phase 3.1 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Assignees
            </label>
            <AssigneePicker
              selectedIds={assignees}
              onChange={(newAssignees) => {
                setAssignees(newAssignees);
                handleFieldBlur('assignees', newAssignees);
              }}
            />
          </div>

          {/* Effort (Story Points) - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Effort (Story Points)
            </label>
            <select
              value={effort || ''}
              onChange={(e) => {
                const newEffort = e.target.value ? (parseInt(e.target.value) as EffortEstimate) : undefined;
                setEffort(newEffort);
                if (task) {
                  updateEffort(task.id, newEffort);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="1">1 - Trivial</option>
              <option value="2">2 - Minor</option>
              <option value="3">3 - Medium</option>
              <option value="5">5 - Major</option>
              <option value="8">8 - Large</option>
              <option value="13">13 - Epic</option>
            </select>
          </div>

          {/* Custom Status - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Custom Status
            </label>
            <select
              value={customStatus || ''}
              onChange={(e) => {
                const newStatus = e.target.value ? (e.target.value as CustomStatus) : undefined;
                setCustomStatus(newStatus);
                if (task) {
                  updateCustomStatus(task.id, newStatus);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="in-review">In Review</option>
              <option value="testing">Testing</option>
              <option value="deployed">Deployed</option>
              <option value="blocked">Blocked</option>
            </select>
          </div>

          {/* Time Estimate - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Time Estimate (hours)
            </label>
            <input
              type="number"
              min="0"
              step="0.5"
              value={timeEstimate || ''}
              onChange={(e) => {
                const hours = e.target.value ? parseFloat(e.target.value) : undefined;
                setTimeEstimate(hours);
                if (task && hours !== undefined) {
                  updateTimeEstimate(task.id, hours);
                }
              }}
              placeholder="e.g., 4.5"
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            />
            {task && (
              <div className="mt-2 space-y-2">
                <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  <span>Actual: {((task.timeTracking?.actual || 0) / 3600).toFixed(1)}h</span>
                  {task.timeTracking?.activeTimerStart && (
                    <span className="animate-pulse text-accent-blue font-semibold">⏱️ Running</span>
                  )}
                </div>
                {task.timeTracking?.activeTimerStart ? (
                  <button
                    onClick={() => stopKanbanTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-status-error text-white text-xs font-medium rounded hover:bg-status-error/90 transition-colors"
                  >
                    ⏹️ Stop Timer
                  </button>
                ) : (
                  <button
                    onClick={() => startTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-accent-blue text-white text-xs font-medium rounded hover:bg-accent-blue-hover transition-colors"
                  >
                    ▶️ Start Timer
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Progress - Phase 1.5 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Progress (%)
            </label>

            {/* Slider */}
            <input
              type="range"
              min="0"
              max="100"
              step="5"
              value={progress}
              onChange={(e) => {
                const newProgress = parseInt(e.target.value);
                setProgress(newProgress);
                handleFieldBlur('progress', newProgress);
              }}
              className="w-full h-2 bg-surface-light-elevated dark:bg-surface-dark rounded-lg appearance-none cursor-pointer accent-accent-blue"
            />

            {/* Numeric input + quick-set buttons */}
            <div className="flex items-center gap-2 mt-2">
              <input
                type="number"
                min="0"
                max="100"
                value={progress}
                onChange={(e) => {
                  const val = Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                  setProgress(val);
                  handleFieldBlur('progress', val);
                }}
                className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">%</span>

              {/* Quick-set buttons */}
              <div className="flex gap-1 ml-auto">
                {[0, 25, 50, 75, 100].map((val) => (
                  <button
                    key={val}
                    onClick={() => {
                      setProgress(val);
                      handleFieldBlur('progress', val);
                    }}
                    className={`px-2 py-1 text-xs rounded transition-colors ${
                      progress === val
                        ? 'bg-accent-blue text-white'
                        : 'bg-neutral-100 dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-200 dark:hover:bg-neutral-700'
                    }`}
                  >
                    {val}%
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Tags */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Tags
            </label>
            <div className="flex flex-wrap gap-2 mb-2">
              {tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-3 py-1 bg-accent-blue text-white text-xs font-medium rounded-full"
                >
                  {tag}
                  <button
                    onClick={() => handleRemoveTag(tag)}
                    className="hover:text-accent-blue-hover"
                    aria-label={`Remove tag ${tag}`}
                  >
                    ✕
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input
                type="text"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add a tag..."
                className="flex-1 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <button
                onClick={handleAddTag}
                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
              >
                Add
              </button>
            </div>
          </div>

          {/* P1: Recurring Tasks */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Recurrence
            </label>

            {/* Show current recurrence or button to add */}
            {!showRecurrencePicker && (
              <div>
                {task?.recurrence ? (
                  <div className="space-y-2">
                    {/* Recurrence Summary */}
                    <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex-1">
                          <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
                            {(() => {
                              const { frequency, interval, daysOfWeek, dayOfMonth } = task.recurrence;
                              let summary = 'Repeats ';

                              // Frequency and interval
                              if (interval === 1) {
                                summary += frequency;
                              } else {
                                summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
                              }

                              // Days of week (for weekly)
                              if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
                                const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
                                const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
                                summary += ` on ${selectedDays}`;
                              }

                              // Day of month (for monthly)
                              if (frequency === 'monthly' && dayOfMonth) {
                                summary += ` on day ${dayOfMonth}`;
                              }

                              return summary;
                            })()}
                          </p>
                          {task.recurrence.endType !== 'never' && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {task.recurrence.endType === 'after' && task.recurrence.endCount &&
                                `Ends after ${task.recurrence.endCount} occurrences`
                              }
                              {task.recurrence.endType === 'until' && task.recurrence.endDate &&
                                `Ends on ${task.recurrence.endDate}`
                              }
                            </p>
                          )}
                          {task.isRecurringParent && task.nextOccurrence && (
                            <p className="text-xs text-accent-blue font-medium mt-1">
                              Next: {task.nextOccurrence}
                            </p>
                          )}
                          {task.recurrenceId && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                              Instance of recurring task
                            </p>
                          )}
                        </div>
                        <button
                          onClick={() => setShowRecurrencePicker(true)}
                          className="text-xs text-accent-blue hover:text-accent-blue-hover"
                        >
                          Edit
                        </button>
                      </div>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => setShowRecurrencePicker(true)}
                    className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
                  >
                    + Add Recurrence
                  </button>
                )}
              </div>
            )}

            {/* Recurrence Picker */}
            {showRecurrencePicker && (
              <div className="mt-2">
                <RecurrencePicker
                  value={task?.recurrence}
                  onChange={(recurrence) => {
                    if (task) {
                      setTaskRecurrence(task.id, recurrence);
                      setShowRecurrencePicker(false);
                    }
                  }}
                  onClose={() => setShowRecurrencePicker(false)}
                />
              </div>
            )}
          </div>

          {/* P2: Save as Template */}
          <div>
            <button
              onClick={handleSaveAsTemplate}
              disabled={!task?.description && (!task?.checklist || task.checklist.length === 0) && (!task?.customFields || Object.keys(task.customFields).length === 0)}
              className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              title="Save this task as a template for recurring tasks"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" />
              </svg>
              Save as Template
            </button>
            <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
              Save this task's description, checklist, and custom fields as a template
            </p>
          </div>

          {/* Dependencies (Professional PM) */}
          <TaskDependenciesSection
            task={task}
            tasks={tasks}
            availableTasks={availableTasks}
            blockedTasks={getBlocked(task.id)}
            onAddDependency={handleAddDependency}
            onRemoveDependency={handleRemoveDependency}
            onCardClick={onCardClick}
          />

          {/* Status */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Status (Column)
            </label>
            <select
              value={status}
              onChange={(e) => {
                const newStatus = e.target.value as TaskStatus;
                setStatus(newStatus);
                handleFieldBlur('status', newStatus);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              {columns.map((column) => (
                <option key={column.id} value={column.id}>
                  {column.title}
                </option>
              ))}
            </select>
          </div>

          {/* Custom Fields (P2 #3) */}
          <TaskCustomFields task={task} onSave={onSave} />
        </div>

        {/* Right Side: Tabs (40%) */}
        <div className="w-full md:w-2/5">
          {/* Tab Navigation */}
          <div className="border-b border-border-light dark:border-border-dark mb-2">
            <div className="flex gap-2">
              <button
                onClick={() => setActiveTab('subtasks')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'subtasks'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Subtasks {task.subtasks && task.subtasks.length > 0 && `(${task.subtasks.length})`}
              </button>
              <button
                onClick={() => setActiveTab('checklist')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'checklist'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Checklist
              </button>
              <button
                onClick={() => setActiveTab('comments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'comments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Comments
              </button>
              <button
                onClick={() => setActiveTab('activity')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'activity'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Activity
              </button>
              <button
                onClick={() => setActiveTab('timetracking')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'timetracking'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Time
              </button>
              <button
                onClick={() => setActiveTab('attachments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'attachments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Attachments {task.attachments && task.attachments.length > 0 && `(${task.attachments.length})`}
              </button>
            </div>
          </div>

          {/* Tab Content */}
          <div className="py-2">
            {/* Subtasks Tab */}
            {activeTab === 'subtasks' && (
              <SubtasksTabContent
                subtasks={task.subtasks}
                onToggle={(subtaskId) => toggleSubtask(task.id, subtaskId)}
                onDelete={(subtaskId) => deleteSubtask(task.id, subtaskId)}
                onAdd={(subtask) => addSubtask(task.id, subtask)}
              />
            )}

            {activeTab === 'checklist' && (
              <ChecklistTabContent
                checklist={task.checklist}
                onToggle={(itemId) => toggleChecklistItem(task.id, itemId)}
                onUpdate={(itemId, updates) => updateChecklistItem(task.id, itemId, updates)}
                onDelete={(itemId) => deleteChecklistItem(task.id, itemId)}
                onAdd={(text) => addChecklistItem(task.id, text)}
              />
            )}

            {activeTab === 'comments' && (
              <CommentsTabContent
                comments={task.comments}
                onAddComment={(text) => addComment(task.id, text)}
              />
            )}

            {activeTab === 'activity' && (
              <ActivityTabContent activityLog={task.activityLog} />
            )}

            {/* Time Tracking Tab (Phase A: Time Tracking Integration) */}
            {activeTab === 'timetracking' && task && (
              <TimeTrackingTabContent
                entries={getEntriesForCard(task.id)}
                totalSeconds={getTotalTimeForCard(task.id)}
                estimatedHours={task.estimatedHours}
                isTimerActive={activeEntry?.taskId === task.id}
                onStartTimer={() => startTimerForCard(task.id, task.title)}
                onStopTimer={() => stopTimer()}
              />
            )}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <AttachmentsTabContent
                attachments={task.attachments || []}
                coverMode={task.coverMode}
                onUpload={(file) => {
                  addAttachment(task.id, {
                    filename: file.filename,
                    fileType: file.fileType,
                    fileSize: file.fileSize,
                    dataUrl: file.dataUrl,
                  });
                }}
                onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                onPreview={(attachment) => setPreviewAttachment(attachment)}
                onCoverModeChange={(mode) => onSave(task.id, { coverMode: mode })}
              />
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Modal } from '../../components/Modal';
import { RecurrencePicker } from '../../components/RecurrencePicker';
import { CustomFieldEditor } from '../../components/CustomFieldEditor';
import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
import AssigneePicker from '../../components/AssigneePicker';
import ImagePreviewModal from '../../components/ImagePreviewModal';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import { useTemplateStore } from '../../stores/useTemplateStore';
import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, TaskDependency, TaskAttachment } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

// Tab Components
import {
  ActivityTabContent,
  AttachmentsTabContent,
  ChecklistTabContent,
  CommentsTabContent,
  SubtasksTabContent,
  TimeTrackingTabContent,
} from './tabs';

// Section Components
import {
  TaskDatesSection,
  TaskDependenciesSection,
} from './sections';

/**
 * TaskCustomFields - Separate component to properly use hooks
 * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
 */
const TaskCustomFields: React.FC<{
  task: Task;
  onSave: (taskId: string, updates: Partial<Task>) => void;
}> = ({ task, onSave }) => {
  const { customFieldDefinitions } = useSettingsStore();
  const taskFields = customFieldDefinitions.tasks;

  if (taskFields.length === 0) return null;

  return (
    <div>
      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
        Custom Fields
      </label>
      <div className="space-y-3">
        {taskFields.map((field: FieldDefinition) => {
          const currentValue = task?.customFields?.[field.id];

          return (
            <div key={field.id}>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                {field.name}
                {field.required && (
                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
                )}
              </label>
              {field.description && (
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  {field.description}
                </p>
              )}
              <CustomFieldEditor
                field={field}
                value={currentValue}
                onChange={(value) => {
                  if (!task) return;
                  const updatedCustomFields = {
                    ...task.customFields,
                    [field.id]: value,
                  };
                  onSave(task.id, { customFields: updatedCustomFields });
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

interface CardDetailPanelProps {
  task: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (taskId: string, updates: Partial<Task>) => void;
  columns: Array<{ id: string; title: string; color: string }>;
  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
  onCardClick?: (task: Task) => void;
}

/**
 * Card Detail Panel
 * Full-screen modal for viewing and editing task details
 *
 * Features:
 * - Left side: Task metadata (title, description, dates, priority, tags, status)
 * - Right side: Tabs (Checklist, Comments, Activity Log)
 * - Inline editing (auto-save on blur)
 * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
 * - Tab persistence (remembers last active tab)
 * - Responsive design (mobile, tablet, desktop)
 */
export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
  task,
  isOpen,
  onClose,
  onSave,
  columns,
  initialTab,
  onCardClick,
}) => {
  // Kanban store actions
  const {
    tasks,
    addChecklistItem,
    updateChecklistItem,
    deleteChecklistItem,
    toggleChecklistItem,
    addComment,
    addSubtask,
    deleteSubtask,
    toggleSubtask,
    addDependency,
    removeDependency,
    getBlocked,
    updateEffort,
    updateCustomStatus,
    startTimer,
    stopTimer: stopKanbanTimer,
    updateTimeEstimate,
    setTaskRecurrence,
    applyDependentShifts,
    addAttachment,
    deleteAttachment,
  } = useKanbanStore();

  // Time tracking store (Phase A: Time Tracking Integration)
  const {
    getEntriesForCard,
    getTotalTimeForCard,
    startTimerForCard,
    stopTimer,
    activeEntry,
  } = useTimeTrackingStore();

  // Template store (P2: Task Templates)
  const { createTemplate } = useTemplateStore();

  // Tab state with persistence
  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
    if (initialTab) return initialTab;
    const saved = localStorage.getItem('kanban-detail-panel-tab');
    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
  });

  // Sync activeTab with initialTab when it changes
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Local state for editing (synced with task prop)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState<string | null>(null);
  const [dueDate, setDueDate] = useState<string | null>(null);
  const [priority, setPriority] = useState<TaskPriority>('medium');
  const [tags, setTags] = useState<string[]>([]);
  const [status, setStatus] = useState<TaskStatus>('todo');
  const [newTag, setNewTag] = useState('');
  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
  const [assignees, setAssignees] = useState<string[]>([]);
  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %

  // P1: Recurring tasks state
  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);

  // Phase 1.2: Auto-shift dependent tasks
  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);

  // Note: Checklist, Comment, and Subtask state moved to extracted tab components

  // Phase 3.2: Attachment state
  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);

  // Phase 2 Quick Wins: Inline date editing
  const [isEditingStartDate, setIsEditingStartDate] = useState(false);
  const [isEditingDueDate, setIsEditingDueDate] = useState(false);

  // No longer need local state for dependency selection - handled by DependencyPicker

  // Sync local state with task prop when task changes
  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description);
      setStartDate(task.startDate);
      setDueDate(task.dueDate);
      setPriority(task.priority);
      setTags(task.tags);
      setStatus(task.status);
      setEffort(task.effort);
      setCustomStatus(task.customStatus);
      setTimeEstimate(task.timeTracking?.estimated);
      setAssignees(task.assignees || []);
      setProgress(task.progress || 0); // Phase 1.5
    }
  }, [task]);

  // Tab persistence
  useEffect(() => {
    localStorage.setItem('kanban-detail-panel-tab', activeTab);
  }, [activeTab]);

  // Save and close handler
  const handleSaveAndClose = useCallback(() => {
    if (!task) return;
    onSave(task.id, {
      title,
      description,
      startDate,
      dueDate,
      priority,
      tags,
      status,
      assignees,
    });
    onClose();
  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status, assignees]);

  // Keyboard shortcut: Cmd+Enter to save and close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
        e.preventDefault();
        handleSaveAndClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, handleSaveAndClose]);

  if (!task) return null;

  const handleFieldBlur = (field: keyof Task, value: unknown) => {
    // Phase 1.2: Check if date change triggers dependent shifts
    if ((field === 'startDate' || field === 'dueDate') && task) {
      const oldStartDate = task.startDate;
      const oldDueDate = task.dueDate;
      const newStartDate = field === 'startDate' ? (value as string | null) : task.startDate;
      const newDueDate = field === 'dueDate' ? (value as string | null) : task.dueDate;

      // Check if auto-shift is enabled and dates actually changed
      if (shouldAutoShift(
        { ...task, startDate: newStartDate, dueDate: newDueDate },
        oldStartDate,
        oldDueDate,
        autoShiftDependentTasks
      )) {
        // Calculate what shifts would be needed
        const shifts = calculateDependentShifts(
          { ...task, startDate: newStartDate, dueDate: newDueDate },
          oldStartDate,
          oldDueDate,
          tasks
        );

        if (shifts.length > 0) {
          // Show confirmation dialog
          setPendingShifts(shifts);
          // Don't save yet - wait for user confirmation
          return;
        }
      }
    }

    // Auto-save on blur (normal case or no shifts needed)
    onSave(task.id, { [field]: value });
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      const updatedTags = [...tags, newTag.trim()];
      setTags(updatedTags);
      onSave(task.id, { tags: updatedTags });
      setNewTag('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    const updatedTags = tags.filter(tag => tag !== tagToRemove);
    setTags(updatedTags);
    onSave(task.id, { tags: updatedTags });
  };

  // Dependency handlers
  const handleAddDependency = (dependency: TaskDependency) => {
    if (!task) return;
    addDependency(task.id, dependency);
  };

  const handleRemoveDependency = (dependencyId: string) => {
    if (!task) return;
    removeDependency(task.id, dependencyId);
  };

  // Phase 1.2: Shift confirmation handlers
  const handleConfirmShifts = () => {
    if (!pendingShifts || !task) return;

    // Apply the date change to the current task first
    const dateField = startDate !== task.startDate ? 'startDate' : 'dueDate';
    const dateValue = startDate !== task.startDate ? startDate : dueDate;
    onSave(task.id, { [dateField]: dateValue });

    // Then apply all dependent shifts
    applyDependentShifts(pendingShifts);

    // Close dialog
    setPendingShifts(null);
  };

  const handleCancelShifts = () => {
    if (!task) return;

    // Revert local state to original values
    setStartDate(task.startDate);
    setDueDate(task.dueDate);

    // Close dialog
    setPendingShifts(null);
  };

  const handleDontAskAgain = () => {
    // Disable auto-shift
    setAutoShiftDependentTasks(false);

    // Close dialog without applying shifts
    handleCancelShifts();
  };

  // P2: Save task as template
  const handleSaveAsTemplate = () => {
    if (!task) return;

    // Check if task has content worth templating
    const hasContent = Boolean(
      task.description ||
      (task.checklist && task.checklist.length > 0) ||
      (task.customFields && Object.keys(task.customFields).length > 0)
    );

    if (!hasContent) {
      alert('Task must have description, checklist, or custom fields to save as template');
      return;
    }

    // Create template from current task
    const template = createTemplate(task);

    // Show success feedback
    alert(`Template "${template.name}" created successfully!`);
  };

  const availableTasks = tasks.filter(t => t.id !== task?.id);

  return (
    <>
    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
      <div className="flex flex-col md:flex-row gap-3 pr-1">
        {/* Left Side: Task Metadata (60%) */}
        <div className="w-full md:w-3/5 space-y-2">
          {/* Title */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Title
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={() => handleFieldBlur('title', title)}
              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onBlur={() => handleFieldBlur('description', description)}
              placeholder="Add a description..."
              className="w-full min-h-[48px] p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-xs text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
              rows={2}
            />
          </div>

          {/* Dates (Inline NL Editing) */}
          <TaskDatesSection
            task={task}
            startDate={startDate}
            setStartDate={setStartDate}
            dueDate={dueDate}
            setDueDate={setDueDate}
            isEditingStartDate={isEditingStartDate}
            setIsEditingStartDate={setIsEditingStartDate}
            isEditingDueDate={isEditingDueDate}
            setIsEditingDueDate={setIsEditingDueDate}
            onFieldBlur={handleFieldBlur}
          />

          {/* Priority */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Priority
            </label>
            <select
              value={priority}
              onChange={(e) => {
                const newPriority = e.target.value as TaskPriority;
                setPriority(newPriority);
                handleFieldBlur('priority', newPriority);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>

          {/* Milestone Checkbox - Phase 1.6 */}
          <div className="flex items-center gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
            <input
              type="checkbox"
              id="is-milestone"
              checked={task?.isMilestone || false}
              onChange={(e) => {
                const isMilestone = e.target.checked;
                handleFieldBlur('isMilestone', isMilestone);

                // If marking as milestone, clear start date (milestones are single-point events)
                if (isMilestone && task?.startDate) {
                  handleFieldBlur('startDate', null);
                  setStartDate(null);
                }
              }}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark text-accent-blue focus:ring-2 focus:ring-accent-blue cursor-pointer"
            />
            <label
              htmlFor="is-milestone"
              className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer select-none"
            >
              📍 Mark as Milestone (key deadline/deliverable)
            </label>
          </div>

          {/* Assignees - Phase 3.1 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Assignees
            </label>
            <AssigneePicker
              selectedIds={assignees}
              onChange={(newAssignees) => {
                setAssignees(newAssignees);
                handleFieldBlur('assignees', newAssignees);
              }}
            />
          </div>

          {/* Effort (Story Points) - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Effort (Story Points)
            </label>
            <select
              value={effort || ''}
              onChange={(e) => {
                const newEffort = e.target.value ? (parseInt(e.target.value) as EffortEstimate) : undefined;
                setEffort(newEffort);
                if (task) {
                  updateEffort(task.id, newEffort);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="1">1 - Trivial</option>
              <option value="2">2 - Minor</option>
              <option value="3">3 - Medium</option>
              <option value="5">5 - Major</option>
              <option value="8">8 - Large</option>
              <option value="13">13 - Epic</option>
            </select>
          </div>

          {/* Custom Status - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Custom Status
            </label>
            <select
              value={customStatus || ''}
              onChange={(e) => {
                const newStatus = e.target.value ? (e.target.value as CustomStatus) : undefined;
                setCustomStatus(newStatus);
                if (task) {
                  updateCustomStatus(task.id, newStatus);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="in-review">In Review</option>
              <option value="testing">Testing</option>
              <option value="deployed">Deployed</option>
              <option value="blocked">Blocked</option>
            </select>
          </div>

          {/* Time Estimate - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Time Estimate (hours)
            </label>
            <input
              type="number"
              min="0"
              step="0.5"
              value={timeEstimate || ''}
              onChange={(e) => {
                const hours = e.target.value ? parseFloat(e.target.value) : undefined;
                setTimeEstimate(hours);
                if (task && hours !== undefined) {
                  updateTimeEstimate(task.id, hours);
                }
              }}
              placeholder="e.g., 4.5"
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            />
            {task && (
              <div className="mt-2 space-y-2">
                <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  <span>Actual: {((task.timeTracking?.actual || 0) / 3600).toFixed(1)}h</span>
                  {task.timeTracking?.activeTimerStart && (
                    <span className="animate-pulse text-accent-blue font-semibold">⏱️ Running</span>
                  )}
                </div>
                {task.timeTracking?.activeTimerStart ? (
                  <button
                    onClick={() => stopKanbanTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-status-error text-white text-xs font-medium rounded hover:bg-status-error/90 transition-colors"
                  >
                    ⏹️ Stop Timer
                  </button>
                ) : (
                  <button
                    onClick={() => startTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-accent-blue text-white text-xs font-medium rounded hover:bg-accent-blue-hover transition-colors"
                  >
                    ▶️ Start Timer
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Progress - Phase 1.5 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Progress (%)
            </label>

            {/* Slider */}
            <input
              type="range"
              min="0"
              max="100"
              step="5"
              value={progress}
              onChange={(e) => {
                const newProgress = parseInt(e.target.value);
                setProgress(newProgress);
                handleFieldBlur('progress', newProgress);
              }}
              className="w-full h-2 bg-surface-light-elevated dark:bg-surface-dark rounded-lg appearance-none cursor-pointer accent-accent-blue"
            />

            {/* Numeric input + quick-set buttons */}
            <div className="flex items-center gap-2 mt-2">
              <input
                type="number"
                min="0"
                max="100"
                value={progress}
                onChange={(e) => {
                  const val = Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                  setProgress(val);
                  handleFieldBlur('progress', val);
                }}
                className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">%</span>

              {/* Quick-set buttons */}
              <div className="flex gap-1 ml-auto">
                {[0, 25, 50, 75, 100].map((val) => (
                  <button
                    key={val}
                    onClick={() => {
                      setProgress(val);
                      handleFieldBlur('progress', val);
                    }}
                    className={`px-2 py-1 text-xs rounded transition-colors ${
                      progress === val
                        ? 'bg-accent-blue text-white'
                        : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                    }`}
                  >
                    {val}%
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Tags */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Tags
            </label>
            <div className="flex flex-wrap gap-2 mb-2">
              {tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-3 py-1 bg-accent-blue text-white text-xs font-medium rounded-full"
                >
                  {tag}
                  <button
                    onClick={() => handleRemoveTag(tag)}
                    className="hover:text-accent-blue-hover"
                    aria-label={`Remove tag ${tag}`}
                  >
                    ✕
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input
                type="text"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add a tag..."
                className="flex-1 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <button
                onClick={handleAddTag}
                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
              >
                Add
              </button>
            </div>
          </div>

          {/* P1: Recurring Tasks */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Recurrence
            </label>

            {/* Show current recurrence or button to add */}
            {!showRecurrencePicker && (
              <div>
                {task?.recurrence ? (
                  <div className="space-y-2">
                    {/* Recurrence Summary */}
                    <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex-1">
                          <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
                            {(() => {
                              const { frequency, interval, daysOfWeek, dayOfMonth } = task.recurrence;
                              let summary = 'Repeats ';

                              // Frequency and interval
                              if (interval === 1) {
                                summary += frequency;
                              } else {
                                summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
                              }

                              // Days of week (for weekly)
                              if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
                                const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
                                const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
                                summary += ` on ${selectedDays}`;
                              }

                              // Day of month (for monthly)
                              if (frequency === 'monthly' && dayOfMonth) {
                                summary += ` on day ${dayOfMonth}`;
                              }

                              return summary;
                            })()}
                          </p>
                          {task.recurrence.endType !== 'never' && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {task.recurrence.endType === 'after' && task.recurrence.endCount &&
                                `Ends after ${task.recurrence.endCount} occurrences`
                              }
                              {task.recurrence.endType === 'until' && task.recurrence.endDate &&
                                `Ends on ${task.recurrence.endDate}`
                              }
                            </p>
                          )}
                          {task.isRecurringParent && task.nextOccurrence && (
                            <p className="text-xs text-accent-blue font-medium mt-1">
                              Next: {task.nextOccurrence}
                            </p>
                          )}
                          {task.recurrenceId && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                              Instance of recurring task
                            </p>
                          )}
                        </div>
                        <button
                          onClick={() => setShowRecurrencePicker(true)}
                          className="text-xs text-accent-blue hover:text-accent-blue-hover"
                        >
                          Edit
                        </button>
                      </div>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => setShowRecurrencePicker(true)}
                    className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors"
                  >
                    + Add Recurrence
                  </button>
                )}
              </div>
            )}

            {/* Recurrence Picker */}
            {showRecurrencePicker && (
              <div className="mt-2">
                <RecurrencePicker
                  value={task?.recurrence}
                  onChange={(recurrence) => {
                    if (task) {
                      setTaskRecurrence(task.id, recurrence);
                      setShowRecurrencePicker(false);
                    }
                  }}
                  onClose={() => setShowRecurrencePicker(false)}
                />
              </div>
            )}
          </div>

          {/* P2: Save as Template */}
          <div>
            <button
              onClick={handleSaveAsTemplate}
              disabled={!task?.description && (!task?.checklist || task.checklist.length === 0) && (!task?.customFields || Object.keys(task.customFields).length === 0)}
              className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              title="Save this task as a template for recurring tasks"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" />
              </svg>
              Save as Template
            </button>
            <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
              Save this task's description, checklist, and custom fields as a template
            </p>
          </div>

          {/* Dependencies (Professional PM) */}
          <TaskDependenciesSection
            task={task}
            tasks={tasks}
            availableTasks={availableTasks}
            blockedTasks={getBlocked(task.id)}
            onAddDependency={handleAddDependency}
            onRemoveDependency={handleRemoveDependency}
            onCardClick={onCardClick}
          />

          {/* Status */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Status (Column)
            </label>
            <select
              value={status}
              onChange={(e) => {
                const newStatus = e.target.value as TaskStatus;
                setStatus(newStatus);
                handleFieldBlur('status', newStatus);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              {columns.map((column) => (
                <option key={column.id} value={column.id}>
                  {column.title}
                </option>
              ))}
            </select>
          </div>

          {/* Custom Fields (P2 #3) */}
          <TaskCustomFields task={task} onSave={onSave} />
        </div>

        {/* Right Side: Tabs (40%) */}
        <div className="w-full md:w-2/5">
          {/* Tab Navigation */}
          <div className="border-b border-border-light dark:border-border-dark mb-2">
            <div className="flex gap-2">
              <button
                onClick={() => setActiveTab('subtasks')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'subtasks'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Subtasks {task.subtasks && task.subtasks.length > 0 && `(${task.subtasks.length})`}
              </button>
              <button
                onClick={() => setActiveTab('checklist')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'checklist'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Checklist
              </button>
              <button
                onClick={() => setActiveTab('comments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'comments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Comments
              </button>
              <button
                onClick={() => setActiveTab('activity')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'activity'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Activity
              </button>
              <button
                onClick={() => setActiveTab('timetracking')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'timetracking'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Time
              </button>
              <button
                onClick={() => setActiveTab('attachments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'attachments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Attachments {task.attachments && task.attachments.length > 0 && `(${task.attachments.length})`}
              </button>
            </div>
          </div>

          {/* Tab Content */}
          <div className="py-2">
            {/* Subtasks Tab */}
            {activeTab === 'subtasks' && (
              <SubtasksTabContent
                subtasks={task.subtasks}
                onToggle={(subtaskId) => toggleSubtask(task.id, subtaskId)}
                onDelete={(subtaskId) => deleteSubtask(task.id, subtaskId)}
                onAdd={(subtask) => addSubtask(task.id, subtask)}
              />
            )}

            {activeTab === 'checklist' && (
              <ChecklistTabContent
                checklist={task.checklist}
                onToggle={(itemId) => toggleChecklistItem(task.id, itemId)}
                onUpdate={(itemId, updates) => updateChecklistItem(task.id, itemId, updates)}
                onDelete={(itemId) => deleteChecklistItem(task.id, itemId)}
                onAdd={(text) => addChecklistItem(task.id, text)}
              />
            )}

            {activeTab === 'comments' && (
              <CommentsTabContent
                comments={task.comments}
                onAddComment={(text) => addComment(task.id, text)}
              />
            )}

            {activeTab === 'activity' && (
              <ActivityTabContent activityLog={task.activityLog} />
            )}

            {/* Time Tracking Tab (Phase A: Time Tracking Integration) */}
            {activeTab === 'timetracking' && task && (
              <TimeTrackingTabContent
                entries={getEntriesForCard(task.id)}
                totalSeconds={getTotalTimeForCard(task.id)}
                estimatedHours={task.estimatedHours}
                isTimerActive={activeEntry?.taskId === task.id}
                onStartTimer={() => startTimerForCard(task.id, task.title)}
                onStopTimer={() => stopTimer()}
              />
            )}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <AttachmentsTabContent
                attachments={task.attachments || []}
                coverMode={task.coverMode}
                onUpload={(file) => {
                  addAttachment(task.id, {
                    filename: file.filename,
                    fileType: file.fileType,
                    fileSize: file.fileSize,
                    dataUrl: file.dataUrl,
                  });
                }}
                onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                onPreview={(attachment) => setPreviewAttachment(attachment)}
                onCoverModeChange={(mode) => onSave(task.id, { coverMode: mode })}
              />
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Modal } from '../../components/Modal';
import { RecurrencePicker } from '../../components/RecurrencePicker';
import { CustomFieldEditor } from '../../components/CustomFieldEditor';
import { DependentShiftConfirmation } from '../../components/DependentShiftConfirmation';
import AssigneePicker from '../../components/AssigneePicker';
import ImagePreviewModal from '../../components/ImagePreviewModal';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useTimeTrackingStore } from '../../stores/useTimeTrackingStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import { useTemplateStore } from '../../stores/useTemplateStore';
import { calculateDependentShifts, shouldAutoShift } from '../../services/taskDependencyShift';
import type { Task, TaskPriority, TaskStatus, EffortEstimate, CustomStatus, TaskDependency, TaskAttachment } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

// Tab Components
import {
  ActivityTabContent,
  AttachmentsTabContent,
  ChecklistTabContent,
  CommentsTabContent,
  SubtasksTabContent,
  TimeTrackingTabContent,
} from './tabs';

// Section Components
import {
  TaskDatesSection,
  TaskDependenciesSection,
} from './sections';

/**
 * TaskCustomFields - Separate component to properly use hooks
 * Extracted to avoid Rules of Hooks violation (hooks cannot be called inside IIFEs)
 */
const TaskCustomFields: React.FC<{
  task: Task;
  onSave: (taskId: string, updates: Partial<Task>) => void;
}> = ({ task, onSave }) => {
  const { customFieldDefinitions } = useSettingsStore();
  const taskFields = customFieldDefinitions.tasks;

  if (taskFields.length === 0) return null;

  return (
    <div>
      <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
        Custom Fields
      </label>
      <div className="space-y-3">
        {taskFields.map((field: FieldDefinition) => {
          const currentValue = task?.customFields?.[field.id];

          return (
            <div key={field.id}>
              <label className="block text-xs font-medium text-text-light-primary dark:text-text-dark-primary mb-1">
                {field.name}
                {field.required && (
                  <span className="text-status-error-text dark:text-status-error-text-dark ml-1">*</span>
                )}
              </label>
              {field.description && (
                <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mb-1">
                  {field.description}
                </p>
              )}
              <CustomFieldEditor
                field={field}
                value={currentValue}
                onChange={(value) => {
                  if (!task) return;
                  const updatedCustomFields = {
                    ...task.customFields,
                    [field.id]: value,
                  };
                  onSave(task.id, { customFields: updatedCustomFields });
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
};

interface CardDetailPanelProps {
  task: Task | null;
  isOpen: boolean;
  onClose: () => void;
  onSave: (taskId: string, updates: Partial<Task>) => void;
  columns: Array<{ id: string; title: string; color: string }>;
  initialTab?: 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments';
  onCardClick?: (task: Task) => void;
}

/**
 * Card Detail Panel
 * Full-screen modal for viewing and editing task details
 *
 * Features:
 * - Left side: Task metadata (title, description, dates, priority, tags, status)
 * - Right side: Tabs (Checklist, Comments, Activity Log)
 * - Inline editing (auto-save on blur)
 * - Keyboard shortcuts (Esc to close, Cmd+Enter to save)
 * - Tab persistence (remembers last active tab)
 * - Responsive design (mobile, tablet, desktop)
 */
export const CardDetailPanel: React.FC<CardDetailPanelProps> = ({
  task,
  isOpen,
  onClose,
  onSave,
  columns,
  initialTab,
  onCardClick,
}) => {
  // Kanban store actions
  const {
    tasks,
    addChecklistItem,
    updateChecklistItem,
    deleteChecklistItem,
    toggleChecklistItem,
    addComment,
    addSubtask,
    deleteSubtask,
    toggleSubtask,
    addDependency,
    removeDependency,
    getBlocked,
    updateEffort,
    updateCustomStatus,
    startTimer,
    stopTimer: stopKanbanTimer,
    updateTimeEstimate,
    setTaskRecurrence,
    applyDependentShifts,
    addAttachment,
    deleteAttachment,
  } = useKanbanStore();

  // Time tracking store (Phase A: Time Tracking Integration)
  const {
    getEntriesForCard,
    getTotalTimeForCard,
    startTimerForCard,
    stopTimer,
    activeEntry,
  } = useTimeTrackingStore();

  // Template store (P2: Task Templates)
  const { createTemplate } = useTemplateStore();

  // Tab state with persistence
  const [activeTab, setActiveTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments'>(() => {
    if (initialTab) return initialTab;
    const saved = localStorage.getItem('kanban-detail-panel-tab');
    return (saved as 'subtasks' | 'checklist' | 'comments' | 'activity' | 'timetracking' | 'attachments') || 'subtasks';
  });

  // Sync activeTab with initialTab when it changes
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Local state for editing (synced with task prop)
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [startDate, setStartDate] = useState<string | null>(null);
  const [dueDate, setDueDate] = useState<string | null>(null);
  const [priority, setPriority] = useState<TaskPriority>('medium');
  const [tags, setTags] = useState<string[]>([]);
  const [status, setStatus] = useState<TaskStatus>('todo');
  const [newTag, setNewTag] = useState('');
  const [effort, setEffort] = useState<EffortEstimate | undefined>(undefined);
  const [customStatus, setCustomStatus] = useState<CustomStatus | undefined>(undefined);
  const [timeEstimate, setTimeEstimate] = useState<number | undefined>(undefined);
  const [assignees, setAssignees] = useState<string[]>([]);
  const [progress, setProgress] = useState<number>(0); // Phase 1.5: Progress %

  // P1: Recurring tasks state
  const [showRecurrencePicker, setShowRecurrencePicker] = useState(false);

  // Phase 1.2: Auto-shift dependent tasks
  const { autoShiftDependentTasks, setAutoShiftDependentTasks } = useSettingsStore();
  const [pendingShifts, setPendingShifts] = useState<Array<{taskId: string; newStartDate: string | null; newDueDate: string | null; reason: string}> | null>(null);

  // Note: Checklist, Comment, and Subtask state moved to extracted tab components

  // Phase 3.2: Attachment state
  const [previewAttachment, setPreviewAttachment] = useState<TaskAttachment | null>(null);

  // Phase 2 Quick Wins: Inline date editing
  const [isEditingStartDate, setIsEditingStartDate] = useState(false);
  const [isEditingDueDate, setIsEditingDueDate] = useState(false);

  // No longer need local state for dependency selection - handled by DependencyPicker

  // Sync local state with task prop when task changes
  useEffect(() => {
    if (task) {
      setTitle(task.title);
      setDescription(task.description);
      setStartDate(task.startDate);
      setDueDate(task.dueDate);
      setPriority(task.priority);
      setTags(task.tags);
      setStatus(task.status);
      setEffort(task.effort);
      setCustomStatus(task.customStatus);
      setTimeEstimate(task.timeTracking?.estimated);
      setAssignees(task.assignees || []);
      setProgress(task.progress || 0); // Phase 1.5
    }
  }, [task]);

  // Tab persistence
  useEffect(() => {
    localStorage.setItem('kanban-detail-panel-tab', activeTab);
  }, [activeTab]);

  // Save and close handler
  const handleSaveAndClose = useCallback(() => {
    if (!task) return;
    onSave(task.id, {
      title,
      description,
      startDate,
      dueDate,
      priority,
      tags,
      status,
      assignees,
    });
    onClose();
  }, [task, onSave, onClose, title, description, startDate, dueDate, priority, tags, status, assignees]);

  // Keyboard shortcut: Cmd+Enter to save and close
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if ((e.metaKey || e.ctrlKey) && e.key === 'Enter' && isOpen) {
        e.preventDefault();
        handleSaveAndClose();
      }
    };

    if (isOpen) {
      document.addEventListener('keydown', handleKeyDown);
    }

    return () => {
      document.removeEventListener('keydown', handleKeyDown);
    };
  }, [isOpen, handleSaveAndClose]);

  if (!task) return null;

  const handleFieldBlur = (field: keyof Task, value: unknown) => {
    // Phase 1.2: Check if date change triggers dependent shifts
    if ((field === 'startDate' || field === 'dueDate') && task) {
      const oldStartDate = task.startDate;
      const oldDueDate = task.dueDate;
      const newStartDate = field === 'startDate' ? (value as string | null) : task.startDate;
      const newDueDate = field === 'dueDate' ? (value as string | null) : task.dueDate;

      // Check if auto-shift is enabled and dates actually changed
      if (shouldAutoShift(
        { ...task, startDate: newStartDate, dueDate: newDueDate },
        oldStartDate,
        oldDueDate,
        autoShiftDependentTasks
      )) {
        // Calculate what shifts would be needed
        const shifts = calculateDependentShifts(
          { ...task, startDate: newStartDate, dueDate: newDueDate },
          oldStartDate,
          oldDueDate,
          tasks
        );

        if (shifts.length > 0) {
          // Show confirmation dialog
          setPendingShifts(shifts);
          // Don't save yet - wait for user confirmation
          return;
        }
      }
    }

    // Auto-save on blur (normal case or no shifts needed)
    onSave(task.id, { [field]: value });
  };

  const handleAddTag = () => {
    if (newTag.trim() && !tags.includes(newTag.trim())) {
      const updatedTags = [...tags, newTag.trim()];
      setTags(updatedTags);
      onSave(task.id, { tags: updatedTags });
      setNewTag('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    const updatedTags = tags.filter(tag => tag !== tagToRemove);
    setTags(updatedTags);
    onSave(task.id, { tags: updatedTags });
  };

  // Dependency handlers
  const handleAddDependency = (dependency: TaskDependency) => {
    if (!task) return;
    addDependency(task.id, dependency);
  };

  const handleRemoveDependency = (dependencyId: string) => {
    if (!task) return;
    removeDependency(task.id, dependencyId);
  };

  // Phase 1.2: Shift confirmation handlers
  const handleConfirmShifts = () => {
    if (!pendingShifts || !task) return;

    // Apply the date change to the current task first
    const dateField = startDate !== task.startDate ? 'startDate' : 'dueDate';
    const dateValue = startDate !== task.startDate ? startDate : dueDate;
    onSave(task.id, { [dateField]: dateValue });

    // Then apply all dependent shifts
    applyDependentShifts(pendingShifts);

    // Close dialog
    setPendingShifts(null);
  };

  const handleCancelShifts = () => {
    if (!task) return;

    // Revert local state to original values
    setStartDate(task.startDate);
    setDueDate(task.dueDate);

    // Close dialog
    setPendingShifts(null);
  };

  const handleDontAskAgain = () => {
    // Disable auto-shift
    setAutoShiftDependentTasks(false);

    // Close dialog without applying shifts
    handleCancelShifts();
  };

  // P2: Save task as template
  const handleSaveAsTemplate = () => {
    if (!task) return;

    // Check if task has content worth templating
    const hasContent = Boolean(
      task.description ||
      (task.checklist && task.checklist.length > 0) ||
      (task.customFields && Object.keys(task.customFields).length > 0)
    );

    if (!hasContent) {
      alert('Task must have description, checklist, or custom fields to save as template');
      return;
    }

    // Create template from current task
    const template = createTemplate(task);

    // Show success feedback
    alert(`Template "${template.name}" created successfully!`);
  };

  const availableTasks = tasks.filter(t => t.id !== task?.id);

  return (
    <>
    <Modal isOpen={isOpen} onClose={onClose} title={task.title} maxWidth="2xl">
      <div className="flex flex-col md:flex-row gap-3 pr-1">
        {/* Left Side: Task Metadata (60%) */}
        <div className="w-full md:w-3/5 space-y-2">
          {/* Title */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Title
            </label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              onBlur={() => handleFieldBlur('title', title)}
              className="w-full text-base font-semibold bg-transparent border-none outline-none text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue rounded px-1 py-0.5"
              autoFocus
            />
          </div>

          {/* Description */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-1">
              Description
            </label>
            <textarea
              value={description}
              onChange={(e) => setDescription(e.target.value)}
              onBlur={() => handleFieldBlur('description', description)}
              placeholder="Add a description..."
              className="w-full min-h-[48px] p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-xs text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none resize-y"
              rows={2}
            />
          </div>

          {/* Dates (Inline NL Editing) */}
          <TaskDatesSection
            task={task}
            startDate={startDate}
            setStartDate={setStartDate}
            dueDate={dueDate}
            setDueDate={setDueDate}
            isEditingStartDate={isEditingStartDate}
            setIsEditingStartDate={setIsEditingStartDate}
            isEditingDueDate={isEditingDueDate}
            setIsEditingDueDate={setIsEditingDueDate}
            onFieldBlur={handleFieldBlur}
          />

          {/* Priority */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Priority
            </label>
            <select
              value={priority}
              onChange={(e) => {
                const newPriority = e.target.value as TaskPriority;
                setPriority(newPriority);
                handleFieldBlur('priority', newPriority);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="low">Low</option>
              <option value="medium">Medium</option>
              <option value="high">High</option>
            </select>
          </div>

          {/* Milestone Checkbox - Phase 1.6 */}
          <div className="flex items-center gap-2 p-3 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded-lg">
            <input
              type="checkbox"
              id="is-milestone"
              checked={task?.isMilestone || false}
              onChange={(e) => {
                const isMilestone = e.target.checked;
                handleFieldBlur('isMilestone', isMilestone);

                // If marking as milestone, clear start date (milestones are single-point events)
                if (isMilestone && task?.startDate) {
                  handleFieldBlur('startDate', null);
                  setStartDate(null);
                }
              }}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark bg-surface-light dark:bg-surface-dark text-accent-blue focus:ring-2 focus:ring-accent-blue cursor-pointer"
            />
            <label
              htmlFor="is-milestone"
              className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary cursor-pointer select-none"
            >
              📍 Mark as Milestone (key deadline/deliverable)
            </label>
          </div>

          {/* Assignees - Phase 3.1 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Assignees
            </label>
            <AssigneePicker
              selectedIds={assignees}
              onChange={(newAssignees) => {
                setAssignees(newAssignees);
                handleFieldBlur('assignees', newAssignees);
              }}
            />
          </div>

          {/* Effort (Story Points) - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Effort (Story Points)
            </label>
            <select
              value={effort || ''}
              onChange={(e) => {
                const newEffort = e.target.value ? (parseInt(e.target.value) as EffortEstimate) : undefined;
                setEffort(newEffort);
                if (task) {
                  updateEffort(task.id, newEffort);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="1">1 - Trivial</option>
              <option value="2">2 - Minor</option>
              <option value="3">3 - Medium</option>
              <option value="5">5 - Major</option>
              <option value="8">8 - Large</option>
              <option value="13">13 - Epic</option>
            </select>
          </div>

          {/* Custom Status - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Custom Status
            </label>
            <select
              value={customStatus || ''}
              onChange={(e) => {
                const newStatus = e.target.value ? (e.target.value as CustomStatus) : undefined;
                setCustomStatus(newStatus);
                if (task) {
                  updateCustomStatus(task.id, newStatus);
                }
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              <option value="">None</option>
              <option value="in-review">In Review</option>
              <option value="testing">Testing</option>
              <option value="deployed">Deployed</option>
              <option value="blocked">Blocked</option>
            </select>
          </div>

          {/* Time Estimate - Phase B */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Time Estimate (hours)
            </label>
            <input
              type="number"
              min="0"
              step="0.5"
              value={timeEstimate || ''}
              onChange={(e) => {
                const hours = e.target.value ? parseFloat(e.target.value) : undefined;
                setTimeEstimate(hours);
                if (task && hours !== undefined) {
                  updateTimeEstimate(task.id, hours);
                }
              }}
              placeholder="e.g., 4.5"
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            />
            {task && (
              <div className="mt-2 space-y-2">
                <div className="flex items-center justify-between text-xs text-text-light-secondary dark:text-text-dark-secondary">
                  <span>Actual: {((task.timeTracking?.actual || 0) / 3600).toFixed(1)}h</span>
                  {task.timeTracking?.activeTimerStart && (
                    <span className="animate-pulse text-accent-blue font-semibold">⏱️ Running</span>
                  )}
                </div>
                {task.timeTracking?.activeTimerStart ? (
                  <button
                    onClick={() => stopKanbanTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-status-error text-white text-xs font-medium rounded hover:bg-status-error/90 transition-colors"
                  >
                    ⏹️ Stop Timer
                  </button>
                ) : (
                  <button
                    onClick={() => startTimer(task.id)}
                    className="w-full px-3 py-1.5 bg-accent-blue text-white text-xs font-medium rounded hover:bg-accent-blue-hover transition-colors"
                  >
                    ▶️ Start Timer
                  </button>
                )}
              </div>
            )}
          </div>

          {/* Progress - Phase 1.5 */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Progress (%)
            </label>

            {/* Slider */}
            <input
              type="range"
              min="0"
              max="100"
              step="5"
              value={progress}
              onChange={(e) => {
                const newProgress = parseInt(e.target.value);
                setProgress(newProgress);
                handleFieldBlur('progress', newProgress);
              }}
              className="w-full h-2 bg-surface-light-elevated dark:bg-surface-dark rounded-lg appearance-none cursor-pointer accent-accent-blue"
            />

            {/* Numeric input + quick-set buttons */}
            <div className="flex items-center gap-2 mt-2">
              <input
                type="number"
                min="0"
                max="100"
                value={progress}
                onChange={(e) => {
                  const val = Math.min(100, Math.max(0, parseInt(e.target.value) || 0));
                  setProgress(val);
                  handleFieldBlur('progress', val);
                }}
                className="w-20 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">%</span>

              {/* Quick-set buttons */}
              <div className="flex gap-1 ml-auto">
                {[0, 25, 50, 75, 100].map((val) => (
                  <button
                    key={val}
                    onClick={() => {
                      setProgress(val);
                      handleFieldBlur('progress', val);
                    }}
                    className={`px-2 py-1 text-xs rounded transition-colors ${
                      progress === val
                        ? 'bg-accent-blue text-white'
                        : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary hover:bg-surface-light dark:hover:bg-surface-dark-elevated'
                    }`}
                  >
                    {val}%
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Tags */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Tags
            </label>
            <div className="flex flex-wrap gap-2 mb-2">
              {tags.map((tag) => (
                <span
                  key={tag}
                  className="inline-flex items-center gap-1 px-3 py-1 bg-accent-blue text-white text-xs font-medium rounded-full"
                >
                  {tag}
                  <button
                    onClick={() => handleRemoveTag(tag)}
                    className="hover:text-accent-blue-hover"
                    aria-label={`Remove tag ${tag}`}
                  >
                    ✕
                  </button>
                </span>
              ))}
            </div>
            <div className="flex gap-2">
              <input
                type="text"
                value={newTag}
                onChange={(e) => setNewTag(e.target.value)}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    handleAddTag();
                  }
                }}
                placeholder="Add a tag..."
                className="flex-1 p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:ring-2 focus:ring-accent-blue outline-none"
              />
              <button
                onClick={handleAddTag}
                className="px-4 py-2 bg-accent-blue hover:bg-accent-blue-hover text-white text-sm font-medium rounded-lg transition-colors"
              >
                Add
              </button>
            </div>
          </div>

          {/* P1: Recurring Tasks */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Recurrence
            </label>

            {/* Show current recurrence or button to add */}
            {!showRecurrencePicker && (
              <div>
                {task?.recurrence ? (
                  <div className="space-y-2">
                    {/* Recurrence Summary */}
                    <div className="p-3 bg-accent-blue/10 dark:bg-accent-blue/20 rounded-lg">
                      <div className="flex items-start justify-between gap-2">
                        <div className="flex-1">
                          <p className="text-xs text-text-light-primary dark:text-text-dark-primary font-medium mb-1">
                            {(() => {
                              const { frequency, interval, daysOfWeek, dayOfMonth } = task.recurrence;
                              let summary = 'Repeats ';

                              // Frequency and interval
                              if (interval === 1) {
                                summary += frequency;
                              } else {
                                summary += `every ${interval} ${frequency === 'daily' ? 'days' : frequency === 'weekly' ? 'weeks' : frequency === 'monthly' ? 'months' : 'years'}`;
                              }

                              // Days of week (for weekly)
                              if (frequency === 'weekly' && daysOfWeek && daysOfWeek.length > 0) {
                                const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
                                const selectedDays = daysOfWeek.map((d) => dayNames[d]).join(', ');
                                summary += ` on ${selectedDays}`;
                              }

                              // Day of month (for monthly)
                              if (frequency === 'monthly' && dayOfMonth) {
                                summary += ` on day ${dayOfMonth}`;
                              }

                              return summary;
                            })()}
                          </p>
                          {task.recurrence.endType !== 'never' && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                              {task.recurrence.endType === 'after' && task.recurrence.endCount &&
                                `Ends after ${task.recurrence.endCount} occurrences`
                              }
                              {task.recurrence.endType === 'until' && task.recurrence.endDate &&
                                `Ends on ${task.recurrence.endDate}`
                              }
                            </p>
                          )}
                          {task.isRecurringParent && task.nextOccurrence && (
                            <p className="text-xs text-accent-blue font-medium mt-1">
                              Next: {task.nextOccurrence}
                            </p>
                          )}
                          {task.recurrenceId && (
                            <p className="text-xs text-text-light-secondary dark:text-text-dark-secondary mt-1">
                              Instance of recurring task
                            </p>
                          )}
                        </div>
                        <button
                          onClick={() => setShowRecurrencePicker(true)}
                          className="text-xs text-accent-blue hover:text-accent-blue-hover"
                        >
                          Edit
                        </button>
                      </div>
                    </div>
                  </div>
                ) : (
                  <button
                    onClick={() => setShowRecurrencePicker(true)}
                    className="w-full p-2 bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-colors"
                  >
                    + Add Recurrence
                  </button>
                )}
              </div>
            )}

            {/* Recurrence Picker */}
            {showRecurrencePicker && (
              <div className="mt-2">
                <RecurrencePicker
                  value={task?.recurrence}
                  onChange={(recurrence) => {
                    if (task) {
                      setTaskRecurrence(task.id, recurrence);
                      setShowRecurrencePicker(false);
                    }
                  }}
                  onClose={() => setShowRecurrencePicker(false)}
                />
              </div>
            )}
          </div>

          {/* P2: Save as Template */}
          <div>
            <button
              onClick={handleSaveAsTemplate}
              disabled={!task?.description && (!task?.checklist || task.checklist.length === 0) && (!task?.customFields || Object.keys(task.customFields).length === 0)}
              className="w-full p-2 bg-surface-light-elevated dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary text-sm rounded-lg hover:bg-surface-light dark:hover:bg-neutral-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center justify-center gap-2"
              title="Save this task as a template for recurring tasks"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z" />
              </svg>
              Save as Template
            </button>
            <p className="mt-1 text-xs text-text-light-secondary dark:text-text-dark-secondary">
              Save this task's description, checklist, and custom fields as a template
            </p>
          </div>

          {/* Dependencies (Professional PM) */}
          <TaskDependenciesSection
            task={task}
            tasks={tasks}
            availableTasks={availableTasks}
            blockedTasks={getBlocked(task.id)}
            onAddDependency={handleAddDependency}
            onRemoveDependency={handleRemoveDependency}
            onCardClick={onCardClick}
          />

          {/* Status */}
          <div>
            <label className="block text-xs font-medium text-text-light-secondary dark:text-text-dark-secondary mb-2">
              Status (Column)
            </label>
            <select
              value={status}
              onChange={(e) => {
                const newStatus = e.target.value as TaskStatus;
                setStatus(newStatus);
                handleFieldBlur('status', newStatus);
              }}
              className="w-full p-2 bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded-lg text-sm text-text-light-primary dark:text-text-dark-primary focus:ring-2 focus:ring-accent-blue outline-none"
            >
              {columns.map((column) => (
                <option key={column.id} value={column.id}>
                  {column.title}
                </option>
              ))}
            </select>
          </div>

          {/* Custom Fields (P2 #3) */}
          <TaskCustomFields task={task} onSave={onSave} />
        </div>

        {/* Right Side: Tabs (40%) */}
        <div className="w-full md:w-2/5">
          {/* Tab Navigation */}
          <div className="border-b border-border-light dark:border-border-dark mb-2">
            <div className="flex gap-2">
              <button
                onClick={() => setActiveTab('subtasks')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'subtasks'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Subtasks {task.subtasks && task.subtasks.length > 0 && `(${task.subtasks.length})`}
              </button>
              <button
                onClick={() => setActiveTab('checklist')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'checklist'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Checklist
              </button>
              <button
                onClick={() => setActiveTab('comments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'comments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Comments
              </button>
              <button
                onClick={() => setActiveTab('activity')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'activity'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Activity
              </button>
              <button
                onClick={() => setActiveTab('timetracking')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'timetracking'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Time
              </button>
              <button
                onClick={() => setActiveTab('attachments')}
                className={`pb-1 px-1 text-xs font-medium transition-colors ${
                  activeTab === 'attachments'
                    ? 'text-accent-blue border-b-2 border-accent-blue'
                    : 'text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary'
                }`}
              >
                Attachments {task.attachments && task.attachments.length > 0 && `(${task.attachments.length})`}
              </button>
            </div>
          </div>

          {/* Tab Content */}
          <div className="py-2">
            {/* Subtasks Tab */}
            {activeTab === 'subtasks' && (
              <SubtasksTabContent
                subtasks={task.subtasks}
                onToggle={(subtaskId) => toggleSubtask(task.id, subtaskId)}
                onDelete={(subtaskId) => deleteSubtask(task.id, subtaskId)}
                onAdd={(subtask) => addSubtask(task.id, subtask)}
              />
            )}

            {activeTab === 'checklist' && (
              <ChecklistTabContent
                checklist={task.checklist}
                onToggle={(itemId) => toggleChecklistItem(task.id, itemId)}
                onUpdate={(itemId, updates) => updateChecklistItem(task.id, itemId, updates)}
                onDelete={(itemId) => deleteChecklistItem(task.id, itemId)}
                onAdd={(text) => addChecklistItem(task.id, text)}
              />
            )}

            {activeTab === 'comments' && (
              <CommentsTabContent
                comments={task.comments}
                onAddComment={(text) => addComment(task.id, text)}
              />
            )}

            {activeTab === 'activity' && (
              <ActivityTabContent activityLog={task.activityLog} />
            )}

            {/* Time Tracking Tab (Phase A: Time Tracking Integration) */}
            {activeTab === 'timetracking' && task && (
              <TimeTrackingTabContent
                entries={getEntriesForCard(task.id)}
                totalSeconds={getTotalTimeForCard(task.id)}
                estimatedHours={task.estimatedHours}
                isTimerActive={activeEntry?.taskId === task.id}
                onStartTimer={() => startTimerForCard(task.id, task.title)}
                onStopTimer={() => stopTimer()}
              />
            )}

            {/* Attachments Tab (Phase 3.2) */}
            {activeTab === 'attachments' && task && (
              <AttachmentsTabContent
                attachments={task.attachments || []}
                coverMode={task.coverMode}
                onUpload={(file) => {
                  addAttachment(task.id, {
                    filename: file.filename,
                    fileType: file.fileType,
                    fileSize: file.fileSize,
                    dataUrl: file.dataUrl,
                  });
                }}
                onDelete={(attachmentId) => deleteAttachment(task.id, attachmentId)}
                onPreview={(attachment) => setPreviewAttachment(attachment)}
                onCoverModeChange={(mode) => onSave(task.id, { coverMode: mode })}
              />
            )}
          </div>
        </div>
      </div>

      {/* Footer: Keyboard Hints */}
      <div className="mt-2 pt-2 border-t border-border-light dark:border-border-dark">
        <p className="text-[10px] text-text-light-secondary dark:text-text-dark-secondary text-center">
          Press <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Esc</kbd> to close
          or <kbd className="px-1 py-0.5 bg-surface-light-elevated dark:bg-surface-dark-elevated rounded text-[10px]">Cmd+Enter</kbd> to save
        </p>
      </div>
    </Modal>

    {/* Phase 1.2: Dependent shift confirmation dialog */}
    {pendingShifts && pendingShifts.length > 0 && (
      <DependentShiftConfirmation
        shifts={pendingShifts}
        tasks={tasks}
        onConfirm={handleConfirmShifts}
        onCancel={handleCancelShifts}
        onDontAskAgain={handleDontAskAgain}
      />
    )}

    {/* Phase 3.2: Image preview modal */}
    {previewAttachment && (
      <ImagePreviewModal
        attachment={previewAttachment}
        onClose={() => setPreviewAttachment(null)}
      />
    )}
    </>
  );
};

import React, { useState, useMemo } from 'react';
import { ConfirmDialog } from '../../components/ConfirmDialog';
import { CustomFieldDisplay } from '../../components/CustomFieldDisplay';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import type { Task, KanbanColumn, TaskPriority, TaskStatus } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

interface ListViewProps {
  tasks: Task[];
  columns: KanbanColumn[];
  onTaskClick: (task: Task) => void;
}

type SortColumn = 'title' | 'status' | 'priority' | 'dueDate' | null;
type SortDirection = 'asc' | 'desc' | null;

/**
 * ListView Component
 * Table format alternative to board view
 *
 * Features:
 * - Sortable columns (title, status, priority, due date)
 * - Bulk select with checkboxes
 * - Bulk actions (change status, priority, delete)
 * - Export to CSV
 * - Row click opens detail panel
 */
export const ListView: React.FC<ListViewProps> = ({ tasks, columns, onTaskClick }) => {
  const { bulkUpdateStatus, bulkUpdatePriority, bulkDeleteTasks } = useKanbanStore();
  const taskFieldDefinitions = useSettingsStore((state) => state.customFieldDefinitions.tasks);

  // Filter to only fields visible in list view
  const visibleFieldDefinitions = useMemo(() => {
    return taskFieldDefinitions.filter(field => field.visibleInList !== false);
  }, [taskFieldDefinitions]);

  // Sorting state
  const [sortColumn, setSortColumn] = useState<SortColumn>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>(null);

  // Bulk selection state
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());

  // Bulk action dialogs
  const [showStatusDialog, setShowStatusDialog] = useState(false);
  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  // Handle column header click for sorting
  const handleSort = (column: SortColumn) => {
    if (sortColumn === column) {
      // Cycle: asc → desc → null
      if (sortDirection === 'asc') {
        setSortDirection('desc');
      } else if (sortDirection === 'desc') {
        setSortColumn(null);
        setSortDirection(null);
      }
    } else {
      setSortColumn(column);
      setSortDirection('asc');
    }
  };

  // Sort tasks based on current sort state
  const sortedTasks = useMemo(() => {
    if (!sortColumn || !sortDirection) return tasks;

    return [...tasks].sort((a, b) => {
      let aValue: string | number | null = null;
      let bValue: string | number | null = null;

      switch (sortColumn) {
        case 'title':
          aValue = a.title.toLowerCase();
          bValue = b.title.toLowerCase();
          break;
        case 'status':
          aValue = columns.findIndex(col => col.id === a.status);
          bValue = columns.findIndex(col => col.id === b.status);
          break;
        case 'priority':
          const priorityOrder = { low: 0, medium: 1, high: 2 };
          aValue = priorityOrder[a.priority];
          bValue = priorityOrder[b.priority];
          break;
        case 'dueDate':
          aValue = a.dueDate ? new Date(a.dueDate).getTime() : Infinity;
          bValue = b.dueDate ? new Date(b.dueDate).getTime() : Infinity;
          break;
      }

      if (aValue === null || aValue === undefined) return 1;
      if (bValue === null || bValue === undefined) return -1;

      if (aValue < bValue) return sortDirection === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });
  }, [tasks, sortColumn, sortDirection, columns]);

  // Toggle select all
  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedTaskIds(new Set(tasks.map(t => t.id)));
    } else {
      setSelectedTaskIds(new Set());
    }
  };

  // Toggle individual task selection
  const handleSelectTask = (taskId: string, checked: boolean) => {
    const newSet = new Set(selectedTaskIds);
    if (checked) {
      newSet.add(taskId);
    } else {
      newSet.delete(taskId);
    }
    setSelectedTaskIds(newSet);
  };

  // Bulk actions
  const handleBulkStatusChange = (status: TaskStatus) => {
    bulkUpdateStatus(Array.from(selectedTaskIds), status);
    setSelectedTaskIds(new Set());
    setShowStatusDialog(false);
  };

  const handleBulkPriorityChange = (priority: TaskPriority) => {
    bulkUpdatePriority(Array.from(selectedTaskIds), priority);
    setSelectedTaskIds(new Set());
    setShowPriorityDialog(false);
  };

  const handleBulkDelete = () => {
    bulkDeleteTasks(Array.from(selectedTaskIds));
    setSelectedTaskIds(new Set());
    setShowDeleteDialog(false);
  };

  // Export CSV
  const handleExportCSV = () => {
    const customFieldHeaders = visibleFieldDefinitions.map(f => f.name);
    const headers = ['Title', 'Status', 'Priority', 'Due Date', 'Tags', 'Subtask Progress', ...customFieldHeaders];
    const rows = tasks.map(task => {
      const statusColumn = columns.find(col => col.id === task.status);
      const status = statusColumn?.title || task.status;
      const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
      const totalSubtasks = task.subtasks?.length || 0;
      const progress = totalSubtasks > 0 ? `${completedSubtasks}/${totalSubtasks}` : 'N/A';

      const customFieldValues = visibleFieldDefinitions.map(field => {
        const value = task.customFields?.[field.id];
        return formatCustomFieldValue(field, value);
      });

      return [
        `"${task.title.replace(/"/g, '""')}"`, // Escape quotes
        status,
        task.priority,
        task.dueDate || 'N/A',
        task.tags.join('; '),
        progress,
        ...customFieldValues,
      ];
    });

    const csv = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `kanban-tasks-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Priority colors
  const priorityColors = {
    low: 'text-status-info',
    medium: 'text-status-warning',
    high: 'text-status-error',
  };

  // Format custom field value for CSV export
  const formatCustomFieldValue = (field: FieldDefinition, value: any): string => {
    if (value === null || value === undefined || value === '') return 'N/A';

    switch (field.type) {
      case 'date':
        const date = new Date(value);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      case 'checkbox':
        return value ? 'Yes' : 'No';
      case 'number':
        return String(value);
      case 'text':
      case 'select':
      default:
        return String(value);
    }
  };

  // Sort indicator
  const getSortIndicator = (column: SortColumn) => {
    if (sortColumn !== column) return null;
    return sortDirection === 'asc' ? ' ▲' : ' ▼';
  };

  const allSelected = tasks.length > 0 && selectedTaskIds.size === tasks.length;
  const someSelected = selectedTaskIds.size > 0 && selectedTaskIds.size < tasks.length;

  return (
    <div className="list-view">
      {/* Bulk Actions Toolbar */}
      {selectedTaskIds.size > 0 && (
        <div className="mb-4 p-3 bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue rounded-lg flex items-center gap-3 flex-wrap">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            {selectedTaskIds.size} selected
          </span>
          <button
            onClick={() => setShowStatusDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Status
          </button>
          <button
            onClick={() => setShowPriorityDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Priority
          </button>
          <button
            onClick={() => setShowDeleteDialog(true)}
            className="px-3 py-1.5 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
          >
            Delete
          </button>
          <button
            onClick={handleExportCSV}
            className="px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors ml-auto"
          >
            Export CSV
          </button>
        </div>
      )}

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="border-b-2 border-border-light dark:border-border-dark">
              <th className="p-3 text-left">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={input => {
                    if (input) input.indeterminate = someSelected;
                  }}
                  onChange={(e) => handleSelectAll(e.target.checked)}
                  className="cursor-pointer"
                />
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('title')}
              >
                Title{getSortIndicator('title')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('status')}
              >
                Status{getSortIndicator('status')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('priority')}
              >
                Priority{getSortIndicator('priority')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors"
                onClick={() => handleSort('dueDate')}
              >
                Due Date{getSortIndicator('dueDate')}
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Tags
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Progress
              </th>
              {/* Custom Field Columns (P1 Feature) */}
              {visibleFieldDefinitions.map(field => (
                <th key={field.id} className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                  {field.name}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sortedTasks.length > 0 ? (
              sortedTasks.map((task) => {
                const statusColumn = columns.find(col => col.id === task.status);
                const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
                const totalSubtasks = task.subtasks?.length || 0;

                return (
                  <tr
                    key={task.id}
                    className="border-b border-border-light dark:border-border-dark hover:bg-neutral-50 dark:hover:bg-neutral-800 transition-colors cursor-pointer"
                    onClick={(e) => {
                      // Don't trigger if clicking checkbox
                      const target = e.target as HTMLElement;
                      if (target.tagName !== 'INPUT') {
                        onTaskClick(task);
                      }
                    }}
                  >
                    <td className="p-3" onClick={(e) => e.stopPropagation()}>
                      <input
                        type="checkbox"
                        checked={selectedTaskIds.has(task.id)}
                        onChange={(e) => handleSelectTask(task.id, e.target.checked)}
                        className="cursor-pointer"
                      />
                    </td>
                    <td className="p-3 font-medium text-text-light-primary dark:text-text-dark-primary">
                      {task.title}
                    </td>
                    <td className="p-3">
                      <span className={`px-2 py-1 text-xs rounded ${statusColumn?.color || 'bg-neutral-200 dark:bg-neutral-700'} text-white`}>
                        {statusColumn?.title || task.status}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`text-sm font-medium ${priorityColors[task.priority]}`}>
                        {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                      </span>
                    </td>
                    <td className="p-3 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}
                    </td>
                    <td className="p-3">
                      <div className="flex gap-1 flex-wrap">
                        {task.tags.slice(0, 3).map(tag => (
                          <span key={tag} className="px-2 py-0.5 text-xs rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue">
                            #{tag}
                          </span>
                        ))}
                        {task.tags.length > 3 && (
                          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                            +{task.tags.length - 3}
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-3">
                      {totalSubtasks > 0 && (
                        <span className={`px-2 py-1 text-xs rounded font-medium ${
                          completedSubtasks === totalSubtasks
                            ? 'bg-status-success text-white'
                            : completedSubtasks > 0
                            ? 'bg-accent-blue text-white'
                            : 'bg-neutral-200 dark:bg-neutral-700 text-text-light-secondary dark:text-text-dark-secondary'
                        }`}>
                          ✓ {completedSubtasks}/{totalSubtasks} subtasks
                        </span>
                      )}
                    </td>
                    {/* Custom Field Cells (P1 Feature) */}
                    {visibleFieldDefinitions.map(field => {
                      const value = task.customFields?.[field.id];
                      return (
                        <td key={field.id} className="p-3">
                          <CustomFieldDisplay
                            field={field}
                            value={value}
                            variant="list"
                          />
                        </td>
                      );
                    })}
                  </tr>
                );
              })
            ) : (
              <tr>
                <td colSpan={7 + visibleFieldDefinitions.length} className="p-12 text-center text-text-light-secondary dark:text-text-dark-secondary">
                  No tasks to display
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Bulk Status Change Dialog */}
      {showStatusDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
