            className="px-3 py-1.5 text-sm bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
          >
            Change Status
          </button>
          <button
            onClick={() => setShowPriorityDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Priority
          </button>
          <button
            onClick={() => setShowDeleteDialog(true)}
            className="px-3 py-1.5 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
          >
            Delete
          </button>
          <button
            onClick={handleExportCSV}
            className="px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors ml-auto"
          >
            Export CSV
          </button>
        </div>
      )}

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="border-b-2 border-border-light dark:border-border-dark">
              <th className="p-3 text-left">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={input => {
                    if (input) input.indeterminate = someSelected;
                  }}
                  onChange={(e) => handleSelectAll(e.target.checked)}
                  className="cursor-pointer"
                />
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('title')}
              >
                Title{getSortIndicator('title')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('status')}
              >
                Status{getSortIndicator('status')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('priority')}
              >
                Priority{getSortIndicator('priority')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('dueDate')}
              >
                Due Date{getSortIndicator('dueDate')}
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Tags
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Progress
              </th>
              {/* Custom Field Columns (P1 Feature) */}
              {visibleFieldDefinitions.map(field => (
                <th key={field.id} className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                  {field.name}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sortedTasks.length > 0 ? (
              sortedTasks.map((task) => {
                const statusColumn = columns.find(col => col.id === task.status);
                const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
                const totalSubtasks = task.subtasks?.length || 0;

                return (
                  <tr
                    key={task.id}
                    className="border-b border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors cursor-pointer"
                    onClick={(e) => {
                      // Don't trigger if clicking checkbox
                      const target = e.target as HTMLElement;
                      if (target.tagName !== 'INPUT') {
                        onTaskClick(task);
                      }
                    }}
                  >
                    <td className="p-3" onClick={(e) => e.stopPropagation()}>
                      <input
                        type="checkbox"
                        checked={selectedTaskIds.has(task.id)}
                        onChange={(e) => handleSelectTask(task.id, e.target.checked)}
                        className="cursor-pointer"
                      />
                    </td>
                    <td className="p-3 font-medium text-text-light-primary dark:text-text-dark-primary">
                      {task.title}
                    </td>
                    <td className="p-3">
                      <span className={`px-2 py-1 text-xs rounded ${statusColumn?.color || 'bg-surface-light-elevated dark:bg-surface-dark'} text-white`}>
                        {statusColumn?.title || task.status}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`text-sm font-medium ${priorityColors[task.priority]}`}>
                        {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                      </span>
                    </td>
                    <td className="p-3 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}
                    </td>
                    <td className="p-3">
                      <div className="flex gap-1 flex-wrap">
                        {task.tags.slice(0, 3).map(tag => (
                          <span key={tag} className="px-2 py-0.5 text-xs rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue">
                            #{tag}
                          </span>
                        ))}
                        {task.tags.length > 3 && (
                          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                            +{task.tags.length - 3}
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-3">
                      {totalSubtasks > 0 && (
                        <span className={`px-2 py-1 text-xs rounded font-medium ${
                          completedSubtasks === totalSubtasks
                            ? 'bg-status-success text-white'
                            : completedSubtasks > 0
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary'
                        }`}>
                          ✓ {completedSubtasks}/{totalSubtasks} subtasks
                        </span>
                      )}
                    </td>
                    {/* Custom Field Cells (P1 Feature) */}
                    {visibleFieldDefinitions.map(field => {
                      const value = task.customFields?.[field.id];
                      return (
                        <td key={field.id} className="p-3">
                          <CustomFieldDisplay
                            field={field}
                            value={value}
                            variant="list"
                          />
                        </td>
                      );
                    })}
                  </tr>
                );
              })
            ) : (
              <tr>
                <td colSpan={7 + visibleFieldDefinitions.length} className="p-12 text-center text-text-light-secondary dark:text-text-dark-secondary">
                  No tasks to display
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Bulk Status Change Dialog */}
      {showStatusDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Status ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {columns.map(column => (
                <button
                  key={column.id}
                  onClick={() => handleBulkStatusChange(column.id as TaskStatus)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                >
                  <span className={`inline-block w-3 h-3 rounded-full mr-2 ${column.color}`}></span>
                  {column.title}
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowStatusDialog(false)}
              className="w-full px-4 py-2 bg-neutral-200 dark:bg-neutral-700 rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Priority Change Dialog */}
      {showPriorityDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Priority ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {(['low', 'medium', 'high'] as TaskPriority[]).map(priority => (
                <button
                  key={priority}
                  onClick={() => handleBulkPriorityChange(priority)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-neutral-100 dark:hover:bg-neutral-700 transition-colors"
                >
                  <span className={`font-medium ${priorityColors[priority]}`}>
                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
                  </span>
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowPriorityDialog(false)}
              className="w-full px-4 py-2 bg-neutral-200 dark:bg-neutral-700 rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={showDeleteDialog}
        onClose={() => setShowDeleteDialog(false)}
        onConfirm={handleBulkDelete}
        title="Delete Tasks"
        message={`Are you sure you want to delete ${selectedTaskIds.size} task(s)? This action cannot be undone.`}
        variant="danger"
      />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ConfirmDialog } from '../../components/ConfirmDialog';
import { CustomFieldDisplay } from '../../components/CustomFieldDisplay';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import type { Task, KanbanColumn, TaskPriority, TaskStatus } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

interface ListViewProps {
  tasks: Task[];
  columns: KanbanColumn[];
  onTaskClick: (task: Task) => void;
}

type SortColumn = 'title' | 'status' | 'priority' | 'dueDate' | null;
type SortDirection = 'asc' | 'desc' | null;

/**
 * ListView Component
 * Table format alternative to board view
 *
 * Features:
 * - Sortable columns (title, status, priority, due date)
 * - Bulk select with checkboxes
 * - Bulk actions (change status, priority, delete)
 * - Export to CSV
 * - Row click opens detail panel
 */
export const ListView: React.FC<ListViewProps> = ({ tasks, columns, onTaskClick }) => {
  const { bulkUpdateStatus, bulkUpdatePriority, bulkDeleteTasks } = useKanbanStore();
  const taskFieldDefinitions = useSettingsStore((state) => state.customFieldDefinitions.tasks);

  // Filter to only fields visible in list view
  const visibleFieldDefinitions = useMemo(() => {
    return taskFieldDefinitions.filter(field => field.visibleInList !== false);
  }, [taskFieldDefinitions]);

  // Sorting state
  const [sortColumn, setSortColumn] = useState<SortColumn>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>(null);

  // Bulk selection state
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());

  // Bulk action dialogs
  const [showStatusDialog, setShowStatusDialog] = useState(false);
  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  // Handle column header click for sorting
  const handleSort = (column: SortColumn) => {
    if (sortColumn === column) {
      // Cycle: asc → desc → null
      if (sortDirection === 'asc') {
        setSortDirection('desc');
      } else if (sortDirection === 'desc') {
        setSortColumn(null);
        setSortDirection(null);
      }
    } else {
      setSortColumn(column);
      setSortDirection('asc');
    }
  };

  // Sort tasks based on current sort state
  const sortedTasks = useMemo(() => {
    if (!sortColumn || !sortDirection) return tasks;

    return [...tasks].sort((a, b) => {
      let aValue: string | number | null = null;
      let bValue: string | number | null = null;

      switch (sortColumn) {
        case 'title':
          aValue = a.title.toLowerCase();
          bValue = b.title.toLowerCase();
          break;
        case 'status':
          aValue = columns.findIndex(col => col.id === a.status);
          bValue = columns.findIndex(col => col.id === b.status);
          break;
        case 'priority':
          const priorityOrder = { low: 0, medium: 1, high: 2 };
          aValue = priorityOrder[a.priority];
          bValue = priorityOrder[b.priority];
          break;
        case 'dueDate':
          aValue = a.dueDate ? new Date(a.dueDate).getTime() : Infinity;
          bValue = b.dueDate ? new Date(b.dueDate).getTime() : Infinity;
          break;
      }

      if (aValue === null || aValue === undefined) return 1;
      if (bValue === null || bValue === undefined) return -1;

      if (aValue < bValue) return sortDirection === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });
  }, [tasks, sortColumn, sortDirection, columns]);

  // Toggle select all
  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedTaskIds(new Set(tasks.map(t => t.id)));
    } else {
      setSelectedTaskIds(new Set());
    }
  };

  // Toggle individual task selection
  const handleSelectTask = (taskId: string, checked: boolean) => {
    const newSet = new Set(selectedTaskIds);
    if (checked) {
      newSet.add(taskId);
    } else {
      newSet.delete(taskId);
    }
    setSelectedTaskIds(newSet);
  };

  // Bulk actions
  const handleBulkStatusChange = (status: TaskStatus) => {
    bulkUpdateStatus(Array.from(selectedTaskIds), status);
    setSelectedTaskIds(new Set());
    setShowStatusDialog(false);
  };

  const handleBulkPriorityChange = (priority: TaskPriority) => {
    bulkUpdatePriority(Array.from(selectedTaskIds), priority);
    setSelectedTaskIds(new Set());
    setShowPriorityDialog(false);
  };

  const handleBulkDelete = () => {
    bulkDeleteTasks(Array.from(selectedTaskIds));
    setSelectedTaskIds(new Set());
    setShowDeleteDialog(false);
  };

  // Export CSV
  const handleExportCSV = () => {
    const customFieldHeaders = visibleFieldDefinitions.map(f => f.name);
    const headers = ['Title', 'Status', 'Priority', 'Due Date', 'Tags', 'Subtask Progress', ...customFieldHeaders];
    const rows = tasks.map(task => {
      const statusColumn = columns.find(col => col.id === task.status);
      const status = statusColumn?.title || task.status;
      const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
      const totalSubtasks = task.subtasks?.length || 0;
      const progress = totalSubtasks > 0 ? `${completedSubtasks}/${totalSubtasks}` : 'N/A';

      const customFieldValues = visibleFieldDefinitions.map(field => {
        const value = task.customFields?.[field.id];
        return formatCustomFieldValue(field, value);
      });

      return [
        `"${task.title.replace(/"/g, '""')}"`, // Escape quotes
        status,
        task.priority,
        task.dueDate || 'N/A',
        task.tags.join('; '),
        progress,
        ...customFieldValues,
      ];
    });

    const csv = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `kanban-tasks-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Priority colors
  const priorityColors = {
    low: 'text-status-info',
    medium: 'text-status-warning',
    high: 'text-status-error',
  };

  // Format custom field value for CSV export
  const formatCustomFieldValue = (field: FieldDefinition, value: any): string => {
    if (value === null || value === undefined || value === '') return 'N/A';

    switch (field.type) {
      case 'date':
        const date = new Date(value);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      case 'checkbox':
        return value ? 'Yes' : 'No';
      case 'number':
        return String(value);
      case 'text':
      case 'select':
      default:
        return String(value);
    }
  };

  // Sort indicator
  const getSortIndicator = (column: SortColumn) => {
    if (sortColumn !== column) return null;
    return sortDirection === 'asc' ? ' ▲' : ' ▼';
  };

  const allSelected = tasks.length > 0 && selectedTaskIds.size === tasks.length;
  const someSelected = selectedTaskIds.size > 0 && selectedTaskIds.size < tasks.length;

  return (
    <div className="list-view">
      {/* Bulk Actions Toolbar */}
      {selectedTaskIds.size > 0 && (
        <div className="mb-4 p-3 bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue rounded-lg flex items-center gap-3 flex-wrap">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            {selectedTaskIds.size} selected
          </span>
          <button
            onClick={() => setShowStatusDialog(true)}
            className="px-3 py-1.5 text-sm bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
          >
            Change Status
          </button>
          <button
            onClick={() => setShowPriorityDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Priority
          </button>
          <button
            onClick={() => setShowDeleteDialog(true)}
            className="px-3 py-1.5 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
          >
            Delete
          </button>
          <button
            onClick={handleExportCSV}
            className="px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors ml-auto"
          >
            Export CSV
          </button>
        </div>
      )}

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="border-b-2 border-border-light dark:border-border-dark">
              <th className="p-3 text-left">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={input => {
                    if (input) input.indeterminate = someSelected;
                  }}
                  onChange={(e) => handleSelectAll(e.target.checked)}
                  className="cursor-pointer"
                />
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('title')}
              >
                Title{getSortIndicator('title')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('status')}
              >
                Status{getSortIndicator('status')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('priority')}
              >
                Priority{getSortIndicator('priority')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('dueDate')}
              >
                Due Date{getSortIndicator('dueDate')}
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Tags
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Progress
              </th>
              {/* Custom Field Columns (P1 Feature) */}
              {visibleFieldDefinitions.map(field => (
                <th key={field.id} className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                  {field.name}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sortedTasks.length > 0 ? (
              sortedTasks.map((task) => {
                const statusColumn = columns.find(col => col.id === task.status);
                const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
                const totalSubtasks = task.subtasks?.length || 0;

                return (
                  <tr
                    key={task.id}
                    className="border-b border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors cursor-pointer"
                    onClick={(e) => {
                      // Don't trigger if clicking checkbox
                      const target = e.target as HTMLElement;
                      if (target.tagName !== 'INPUT') {
                        onTaskClick(task);
                      }
                    }}
                  >
                    <td className="p-3" onClick={(e) => e.stopPropagation()}>
                      <input
                        type="checkbox"
                        checked={selectedTaskIds.has(task.id)}
                        onChange={(e) => handleSelectTask(task.id, e.target.checked)}
                        className="cursor-pointer"
                      />
                    </td>
                    <td className="p-3 font-medium text-text-light-primary dark:text-text-dark-primary">
                      {task.title}
                    </td>
                    <td className="p-3">
                      <span className={`px-2 py-1 text-xs rounded ${statusColumn?.color || 'bg-surface-light-elevated dark:bg-surface-dark'} text-white`}>
                        {statusColumn?.title || task.status}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`text-sm font-medium ${priorityColors[task.priority]}`}>
                        {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                      </span>
                    </td>
                    <td className="p-3 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}
                    </td>
                    <td className="p-3">
                      <div className="flex gap-1 flex-wrap">
                        {task.tags.slice(0, 3).map(tag => (
                          <span key={tag} className="px-2 py-0.5 text-xs rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue">
                            #{tag}
                          </span>
                        ))}
                        {task.tags.length > 3 && (
                          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                            +{task.tags.length - 3}
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-3">
                      {totalSubtasks > 0 && (
                        <span className={`px-2 py-1 text-xs rounded font-medium ${
                          completedSubtasks === totalSubtasks
                            ? 'bg-status-success text-white'
                            : completedSubtasks > 0
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary'
                        }`}>
                          ✓ {completedSubtasks}/{totalSubtasks} subtasks
                        </span>
                      )}
                    </td>
                    {/* Custom Field Cells (P1 Feature) */}
                    {visibleFieldDefinitions.map(field => {
                      const value = task.customFields?.[field.id];
                      return (
                        <td key={field.id} className="p-3">
                          <CustomFieldDisplay
                            field={field}
                            value={value}
                            variant="list"
                          />
                        </td>
                      );
                    })}
                  </tr>
                );
              })
            ) : (
              <tr>
                <td colSpan={7 + visibleFieldDefinitions.length} className="p-12 text-center text-text-light-secondary dark:text-text-dark-secondary">
                  No tasks to display
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Bulk Status Change Dialog */}
      {showStatusDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Status ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {columns.map(column => (
                <button
                  key={column.id}
                  onClick={() => handleBulkStatusChange(column.id as TaskStatus)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                >
                  <span className={`inline-block w-3 h-3 rounded-full mr-2 ${column.color}`}></span>
                  {column.title}
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowStatusDialog(false)}
              className="w-full px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Priority Change Dialog */}
      {showPriorityDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Priority ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {(['low', 'medium', 'high'] as TaskPriority[]).map(priority => (
                <button
                  key={priority}
                  onClick={() => handleBulkPriorityChange(priority)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-neutral-100 dark:hover:bg-neutral-700 transition-colors"
                >
                  <span className={`font-medium ${priorityColors[priority]}`}>
                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
                  </span>
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowPriorityDialog(false)}
              className="w-full px-4 py-2 bg-neutral-200 dark:bg-neutral-700 rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={showDeleteDialog}
        onClose={() => setShowDeleteDialog(false)}
        onConfirm={handleBulkDelete}
        title="Delete Tasks"
        message={`Are you sure you want to delete ${selectedTaskIds.size} task(s)? This action cannot be undone.`}
        variant="danger"
      />
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { ConfirmDialog } from '../../components/ConfirmDialog';
import { CustomFieldDisplay } from '../../components/CustomFieldDisplay';
import { useKanbanStore } from '../../stores/useKanbanStore';
import { useSettingsStore } from '../../stores/useSettingsStore';
import type { Task, KanbanColumn, TaskPriority, TaskStatus } from '../../types';
import type { FieldDefinition } from '../../types/customFields';

interface ListViewProps {
  tasks: Task[];
  columns: KanbanColumn[];
  onTaskClick: (task: Task) => void;
}

type SortColumn = 'title' | 'status' | 'priority' | 'dueDate' | null;
type SortDirection = 'asc' | 'desc' | null;

/**
 * ListView Component
 * Table format alternative to board view
 *
 * Features:
 * - Sortable columns (title, status, priority, due date)
 * - Bulk select with checkboxes
 * - Bulk actions (change status, priority, delete)
 * - Export to CSV
 * - Row click opens detail panel
 */
export const ListView: React.FC<ListViewProps> = ({ tasks, columns, onTaskClick }) => {
  const { bulkUpdateStatus, bulkUpdatePriority, bulkDeleteTasks } = useKanbanStore();
  const taskFieldDefinitions = useSettingsStore((state) => state.customFieldDefinitions.tasks);

  // Filter to only fields visible in list view
  const visibleFieldDefinitions = useMemo(() => {
    return taskFieldDefinitions.filter(field => field.visibleInList !== false);
  }, [taskFieldDefinitions]);

  // Sorting state
  const [sortColumn, setSortColumn] = useState<SortColumn>(null);
  const [sortDirection, setSortDirection] = useState<SortDirection>(null);

  // Bulk selection state
  const [selectedTaskIds, setSelectedTaskIds] = useState<Set<string>>(new Set());

  // Bulk action dialogs
  const [showStatusDialog, setShowStatusDialog] = useState(false);
  const [showPriorityDialog, setShowPriorityDialog] = useState(false);
  const [showDeleteDialog, setShowDeleteDialog] = useState(false);

  // Handle column header click for sorting
  const handleSort = (column: SortColumn) => {
    if (sortColumn === column) {
      // Cycle: asc → desc → null
      if (sortDirection === 'asc') {
        setSortDirection('desc');
      } else if (sortDirection === 'desc') {
        setSortColumn(null);
        setSortDirection(null);
      }
    } else {
      setSortColumn(column);
      setSortDirection('asc');
    }
  };

  // Sort tasks based on current sort state
  const sortedTasks = useMemo(() => {
    if (!sortColumn || !sortDirection) return tasks;

    return [...tasks].sort((a, b) => {
      let aValue: string | number | null = null;
      let bValue: string | number | null = null;

      switch (sortColumn) {
        case 'title':
          aValue = a.title.toLowerCase();
          bValue = b.title.toLowerCase();
          break;
        case 'status':
          aValue = columns.findIndex(col => col.id === a.status);
          bValue = columns.findIndex(col => col.id === b.status);
          break;
        case 'priority':
          const priorityOrder = { low: 0, medium: 1, high: 2 };
          aValue = priorityOrder[a.priority];
          bValue = priorityOrder[b.priority];
          break;
        case 'dueDate':
          aValue = a.dueDate ? new Date(a.dueDate).getTime() : Infinity;
          bValue = b.dueDate ? new Date(b.dueDate).getTime() : Infinity;
          break;
      }

      if (aValue === null || aValue === undefined) return 1;
      if (bValue === null || bValue === undefined) return -1;

      if (aValue < bValue) return sortDirection === 'asc' ? -1 : 1;
      if (aValue > bValue) return sortDirection === 'asc' ? 1 : -1;
      return 0;
    });
  }, [tasks, sortColumn, sortDirection, columns]);

  // Toggle select all
  const handleSelectAll = (checked: boolean) => {
    if (checked) {
      setSelectedTaskIds(new Set(tasks.map(t => t.id)));
    } else {
      setSelectedTaskIds(new Set());
    }
  };

  // Toggle individual task selection
  const handleSelectTask = (taskId: string, checked: boolean) => {
    const newSet = new Set(selectedTaskIds);
    if (checked) {
      newSet.add(taskId);
    } else {
      newSet.delete(taskId);
    }
    setSelectedTaskIds(newSet);
  };

  // Bulk actions
  const handleBulkStatusChange = (status: TaskStatus) => {
    bulkUpdateStatus(Array.from(selectedTaskIds), status);
    setSelectedTaskIds(new Set());
    setShowStatusDialog(false);
  };

  const handleBulkPriorityChange = (priority: TaskPriority) => {
    bulkUpdatePriority(Array.from(selectedTaskIds), priority);
    setSelectedTaskIds(new Set());
    setShowPriorityDialog(false);
  };

  const handleBulkDelete = () => {
    bulkDeleteTasks(Array.from(selectedTaskIds));
    setSelectedTaskIds(new Set());
    setShowDeleteDialog(false);
  };

  // Export CSV
  const handleExportCSV = () => {
    const customFieldHeaders = visibleFieldDefinitions.map(f => f.name);
    const headers = ['Title', 'Status', 'Priority', 'Due Date', 'Tags', 'Subtask Progress', ...customFieldHeaders];
    const rows = tasks.map(task => {
      const statusColumn = columns.find(col => col.id === task.status);
      const status = statusColumn?.title || task.status;
      const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
      const totalSubtasks = task.subtasks?.length || 0;
      const progress = totalSubtasks > 0 ? `${completedSubtasks}/${totalSubtasks}` : 'N/A';

      const customFieldValues = visibleFieldDefinitions.map(field => {
        const value = task.customFields?.[field.id];
        return formatCustomFieldValue(field, value);
      });

      return [
        `"${task.title.replace(/"/g, '""')}"`, // Escape quotes
        status,
        task.priority,
        task.dueDate || 'N/A',
        task.tags.join('; '),
        progress,
        ...customFieldValues,
      ];
    });

    const csv = [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `kanban-tasks-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(url);
  };

  // Priority colors
  const priorityColors = {
    low: 'text-status-info',
    medium: 'text-status-warning',
    high: 'text-status-error',
  };

  // Format custom field value for CSV export
  const formatCustomFieldValue = (field: FieldDefinition, value: any): string => {
    if (value === null || value === undefined || value === '') return 'N/A';

    switch (field.type) {
      case 'date':
        const date = new Date(value);
        return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
      case 'checkbox':
        return value ? 'Yes' : 'No';
      case 'number':
        return String(value);
      case 'text':
      case 'select':
      default:
        return String(value);
    }
  };

  // Sort indicator
  const getSortIndicator = (column: SortColumn) => {
    if (sortColumn !== column) return null;
    return sortDirection === 'asc' ? ' ▲' : ' ▼';
  };

  const allSelected = tasks.length > 0 && selectedTaskIds.size === tasks.length;
  const someSelected = selectedTaskIds.size > 0 && selectedTaskIds.size < tasks.length;

  return (
    <div className="list-view">
      {/* Bulk Actions Toolbar */}
      {selectedTaskIds.size > 0 && (
        <div className="mb-4 p-3 bg-accent-blue/10 dark:bg-accent-blue/20 border border-accent-blue rounded-lg flex items-center gap-3 flex-wrap">
          <span className="text-sm font-medium text-text-light-primary dark:text-text-dark-primary">
            {selectedTaskIds.size} selected
          </span>
          <button
            onClick={() => setShowStatusDialog(true)}
            className="px-3 py-1.5 text-sm bg-surface-light dark:bg-surface-dark border border-border-light dark:border-border-dark rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark-elevated transition-colors"
          >
            Change Status
          </button>
          <button
            onClick={() => setShowPriorityDialog(true)}
            className="px-3 py-1.5 text-sm bg-white dark:bg-neutral-800 border border-border-light dark:border-border-dark rounded hover:bg-neutral-50 dark:hover:bg-neutral-700 transition-colors"
          >
            Change Priority
          </button>
          <button
            onClick={() => setShowDeleteDialog(true)}
            className="px-3 py-1.5 text-sm bg-status-error text-white rounded hover:opacity-80 transition-opacity"
          >
            Delete
          </button>
          <button
            onClick={handleExportCSV}
            className="px-3 py-1.5 text-sm bg-accent-blue text-white rounded hover:bg-accent-blue-hover transition-colors ml-auto"
          >
            Export CSV
          </button>
        </div>
      )}

      {/* Table */}
      <div className="overflow-x-auto">
        <table className="w-full border-collapse">
          <thead>
            <tr className="border-b-2 border-border-light dark:border-border-dark">
              <th className="p-3 text-left">
                <input
                  type="checkbox"
                  checked={allSelected}
                  ref={input => {
                    if (input) input.indeterminate = someSelected;
                  }}
                  onChange={(e) => handleSelectAll(e.target.checked)}
                  className="cursor-pointer"
                />
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('title')}
              >
                Title{getSortIndicator('title')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('status')}
              >
                Status{getSortIndicator('status')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('priority')}
              >
                Priority{getSortIndicator('priority')}
              </th>
              <th
                className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary cursor-pointer hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                onClick={() => handleSort('dueDate')}
              >
                Due Date{getSortIndicator('dueDate')}
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Tags
              </th>
              <th className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                Progress
              </th>
              {/* Custom Field Columns (P1 Feature) */}
              {visibleFieldDefinitions.map(field => (
                <th key={field.id} className="p-3 text-left font-semibold text-text-light-primary dark:text-text-dark-primary">
                  {field.name}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {sortedTasks.length > 0 ? (
              sortedTasks.map((task) => {
                const statusColumn = columns.find(col => col.id === task.status);
                const completedSubtasks = task.subtasks?.filter(st => st.completed).length || 0;
                const totalSubtasks = task.subtasks?.length || 0;

                return (
                  <tr
                    key={task.id}
                    className="border-b border-border-light dark:border-border-dark hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors cursor-pointer"
                    onClick={(e) => {
                      // Don't trigger if clicking checkbox
                      const target = e.target as HTMLElement;
                      if (target.tagName !== 'INPUT') {
                        onTaskClick(task);
                      }
                    }}
                  >
                    <td className="p-3" onClick={(e) => e.stopPropagation()}>
                      <input
                        type="checkbox"
                        checked={selectedTaskIds.has(task.id)}
                        onChange={(e) => handleSelectTask(task.id, e.target.checked)}
                        className="cursor-pointer"
                      />
                    </td>
                    <td className="p-3 font-medium text-text-light-primary dark:text-text-dark-primary">
                      {task.title}
                    </td>
                    <td className="p-3">
                      <span className={`px-2 py-1 text-xs rounded ${statusColumn?.color || 'bg-surface-light-elevated dark:bg-surface-dark'} text-white`}>
                        {statusColumn?.title || task.status}
                      </span>
                    </td>
                    <td className="p-3">
                      <span className={`text-sm font-medium ${priorityColors[task.priority]}`}>
                        {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
                      </span>
                    </td>
                    <td className="p-3 text-sm text-text-light-secondary dark:text-text-dark-secondary">
                      {task.dueDate ? new Date(task.dueDate).toLocaleDateString() : '—'}
                    </td>
                    <td className="p-3">
                      <div className="flex gap-1 flex-wrap">
                        {task.tags.slice(0, 3).map(tag => (
                          <span key={tag} className="px-2 py-0.5 text-xs rounded bg-accent-blue/10 dark:bg-accent-blue/20 text-accent-blue">
                            #{tag}
                          </span>
                        ))}
                        {task.tags.length > 3 && (
                          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
                            +{task.tags.length - 3}
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="p-3">
                      {totalSubtasks > 0 && (
                        <span className={`px-2 py-1 text-xs rounded font-medium ${
                          completedSubtasks === totalSubtasks
                            ? 'bg-status-success text-white'
                            : completedSubtasks > 0
                            ? 'bg-accent-blue text-white'
                            : 'bg-surface-light-elevated dark:bg-surface-dark text-text-light-secondary dark:text-text-dark-secondary'
                        }`}>
                          ✓ {completedSubtasks}/{totalSubtasks} subtasks
                        </span>
                      )}
                    </td>
                    {/* Custom Field Cells (P1 Feature) */}
                    {visibleFieldDefinitions.map(field => {
                      const value = task.customFields?.[field.id];
                      return (
                        <td key={field.id} className="p-3">
                          <CustomFieldDisplay
                            field={field}
                            value={value}
                            variant="list"
                          />
                        </td>
                      );
                    })}
                  </tr>
                );
              })
            ) : (
              <tr>
                <td colSpan={7 + visibleFieldDefinitions.length} className="p-12 text-center text-text-light-secondary dark:text-text-dark-secondary">
                  No tasks to display
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Bulk Status Change Dialog */}
      {showStatusDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Status ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {columns.map(column => (
                <button
                  key={column.id}
                  onClick={() => handleBulkStatusChange(column.id as TaskStatus)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                >
                  <span className={`inline-block w-3 h-3 rounded-full mr-2 ${column.color}`}></span>
                  {column.title}
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowStatusDialog(false)}
              className="w-full px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Priority Change Dialog */}
      {showPriorityDialog && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-surface-light dark:bg-surface-dark rounded-lg p-6 max-w-md w-full mx-4">
            <h3 className="text-lg font-semibold mb-4 text-text-light-primary dark:text-text-dark-primary">
              Change Priority ({selectedTaskIds.size} tasks)
            </h3>
            <div className="space-y-2 mb-6">
              {(['low', 'medium', 'high'] as TaskPriority[]).map(priority => (
                <button
                  key={priority}
                  onClick={() => handleBulkPriorityChange(priority)}
                  className="w-full text-left px-4 py-2 rounded hover:bg-surface-light-elevated dark:hover:bg-surface-dark transition-colors"
                >
                  <span className={`font-medium ${priorityColors[priority]}`}>
                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
                  </span>
                </button>
              ))}
            </div>
            <button
              onClick={() => setShowPriorityDialog(false)}
              className="w-full px-4 py-2 bg-neutral-200 dark:bg-neutral-700 rounded hover:opacity-80 transition-opacity"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      {/* Bulk Delete Confirmation */}
      <ConfirmDialog
        isOpen={showDeleteDialog}
        onClose={() => setShowDeleteDialog(false)}
        onConfirm={handleBulkDelete}
        title="Delete Tasks"
        message={`Are you sure you want to delete ${selectedTaskIds.size} task(s)? This action cannot be undone.`}
        variant="danger"
      />
    </div>
  );
};

import { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { useKanbanStore } from '../../stores/useKanbanStore';

interface ArchivedViewProps {
  isOpen: boolean;
  onClose: () => void;
}

/**
 * ArchivedView - Modal to view and manage archived tasks
 * Phase A: Quick Wins - Archive System
 */
export function ArchivedView({ isOpen, onClose }: ArchivedViewProps) {
  const { getArchivedTasks, restoreTask, deleteArchivedTask } = useKanbanStore();
  const [searchQuery, setSearchQuery] = useState('');
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const archivedTasks = getArchivedTasks();

  // Filter archived tasks by search query
  const filteredTasks = archivedTasks.filter((task) =>
    task.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    task.description?.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleRestore = (taskId: string) => {
    restoreTask(taskId);
  };

  const handleDelete = (taskId: string) => {
    deleteArchivedTask(taskId);
    setDeleteConfirmId(null);
  };

  const formatDate = (dateString?: string) => {
    if (!dateString) return 'Unknown date';
    const date = new Date(dateString);
    return date.toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  if (!isOpen) return null;

  return (
    <AnimatePresence>
      <div className="fixed inset-0 z-50 flex items-center justify-center">
        {/* Backdrop */}
        <motion.div
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          className="absolute inset-0 bg-black/50"
          onClick={onClose}
        />

        {/* Modal */}
        <motion.div
          initial={{ opacity: 0, scale: 0.95 }}
          animate={{ opacity: 1, scale: 1 }}
          exit={{ opacity: 0, scale: 0.95 }}
          className="relative w-full max-w-4xl max-h-[80vh] mx-4 bg-surface-light dark:bg-surface-dark-elevated rounded-lg shadow-2xl border border-border-light dark:border-border-dark overflow-hidden flex flex-col"
        >
          {/* Header */}
          <div className="flex items-center justify-between px-6 py-4 border-b border-border-light dark:border-border-dark">
            <div>
              <h2 className="text-xl font-semibold text-text-light-primary dark:text-text-dark-primary">
                Archived Tasks
              </h2>
              <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1">
                {archivedTasks.length} archived {archivedTasks.length === 1 ? 'task' : 'tasks'}
              </p>
            </div>
            <button
              onClick={onClose}
              className="p-2 rounded-lg hover:bg-surface-light-elevated dark:hover:bg-neutral-800 transition-colors"
              aria-label="Close archived view"
            >
              <span className="text-2xl text-text-light-secondary dark:text-text-dark-secondary">×</span>
            </button>
          </div>

          {/* Search */}
          <div className="px-6 py-4 border-b border-border-light dark:border-border-dark">
            <input
              type="text"
              placeholder="Search archived tasks..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full px-4 py-2 bg-surface-light-elevated dark:bg-surface-dark rounded-lg border border-border-light dark:border-border-dark text-text-light-primary dark:text-text-dark-primary placeholder:text-text-light-secondary dark:placeholder:text-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-blue"
            />
          </div>

          {/* Task List */}
          <div className="flex-1 overflow-y-auto px-6 py-4">
            {filteredTasks.length === 0 ? (
              <div className="text-center py-12">
                <p className="text-text-light-secondary dark:text-text-dark-secondary text-lg">
                  {searchQuery ? 'No archived tasks found' : 'No archived tasks yet'}
                </p>
                <p className="text-text-light-secondary dark:text-text-dark-secondary text-sm mt-2">
                  {searchQuery ? 'Try a different search term' : 'Completed tasks will be auto-archived after 14 days'}
                </p>
              </div>
            ) : (
              <div className="space-y-3">
                {filteredTasks.map((task) => (
                  <motion.div
                    key={task.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="p-4 bg-surface-light-elevated dark:bg-surface-dark rounded-lg border border-border-light dark:border-border-dark"
                  >
                    <div className="flex items-start justify-between gap-4">
                      <div className="flex-1 min-w-0">
                        <h3 className="font-semibold text-text-light-primary dark:text-text-dark-primary truncate">
                          {task.title}
                        </h3>
                        {task.description && (
                          <p className="text-sm text-text-light-secondary dark:text-text-dark-secondary mt-1 line-clamp-2">
                            {task.description}
                          </p>
                        )}
                        <div className="flex items-center gap-4 mt-2 text-xs text-text-light-secondary dark:text-text-dark-secondary">
                          <span>Archived: {formatDate(task.archivedAt)}</span>
                          {task.priority && (
                            <span
